/**
 * Message Templates Editor
 * 
 * Component for managing WhatsApp message templates
 */

import React, { useState, useEffect } from 'react';
import {
    FileText,
    Plus,
    Trash2,
    X,
    Edit2,
    Check
} from 'lucide-react';
import {
    getMessageTemplates,
    saveMessageTemplates,
    type MessageTemplate
} from '../../services/integrations/whatsapp/whatsappService';

export const MessageTemplatesEditor: React.FC = () => {
    const [templates, setTemplates] = useState<MessageTemplate[]>([]);
    const [loading, setLoading] = useState(true);
    const [editingId, setEditingId] = useState<string | null>(null);
    const [editContent, setEditContent] = useState('');

    const loadTemplates = async () => {
        setLoading(true);
        const data = await getMessageTemplates();
        setTemplates(data);
        setLoading(false);
    };

    useEffect(() => {
        loadTemplates();
    }, []);

    const handleEdit = (template: MessageTemplate) => {
        setEditingId(template.id || null);
        setEditContent(template.content);
    };

    const handleSaveEdit = async (templateId: string) => {
        const updated = templates.map(t =>
            t.id === templateId ? { ...t, content: editContent } : t
        );

        await saveMessageTemplates(updated);
        setTemplates(updated);
        setEditingId(null);
    };

    const handleCancelEdit = () => {
        setEditingId(null);
        setEditContent('');
    };

    const handleAddTemplate = async () => {
        const newTemplate: MessageTemplate = {
            id: `custom-${Date.now()}`,
            name: 'Nueva Plantilla',
            type: 'custom',
            content: '📋 Escribe tu mensaje aquí...\n\nVariables disponibles:\n{{date}} - Fecha\n{{signedBy}} - Firmado por\n{{signedAt}} - Hora firma\n{{hospitalized}} - Hospitalizados\n{{handoffUrl}} - Link'
        };

        const updated = [...templates, newTemplate];
        await saveMessageTemplates(updated);
        setTemplates(updated);
        handleEdit(newTemplate);
    };

    const handleDeleteTemplate = async (templateId: string) => {
        if (!confirm('¿Eliminar esta plantilla?')) return;

        const updated = templates.filter(t => t.id !== templateId);
        await saveMessageTemplates(updated);
        setTemplates(updated);
    };

    if (loading) {
        return <div className="text-center py-8">Cargando plantillas...</div>;
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <FileText className="w-5 h-5 text-purple-500" />
                    <h3 className="font-medium">Plantillas de Mensaje</h3>
                </div>
                <button
                    onClick={handleAddTemplate}
                    className="flex items-center gap-1 px-3 py-1.5 text-sm bg-purple-600 text-white rounded-lg hover:bg-purple-700"
                >
                    <Plus className="w-4 h-4" />
                    Nueva
                </button>
            </div>

            <div className="space-y-3">
                {templates.map(template => (
                    <div
                        key={template.id}
                        className="border rounded-lg p-4 bg-white"
                    >
                        <div className="flex items-center justify-between mb-2">
                            <div className="flex items-center gap-2">
                                <span className="font-medium">{template.name}</span>
                                <span className={`text-xs px-2 py-0.5 rounded ${template.type === 'handoff'
                                    ? 'bg-green-100 text-green-700'
                                    : template.type === 'shift'
                                        ? 'bg-blue-100 text-blue-700'
                                        : 'bg-gray-100 text-gray-700'
                                    }`}>
                                    {template.type === 'handoff' ? 'Entrega' :
                                        template.type === 'shift' ? 'Turno' : 'Custom'}
                                </span>
                            </div>

                            <div className="flex items-center gap-1">
                                {editingId === template.id ? (
                                    <>
                                        <button
                                            onClick={() => handleSaveEdit(template.id!)}
                                            className="p-1.5 text-green-600 hover:bg-green-50 rounded"
                                            title="Guardar"
                                        >
                                            <Check className="w-4 h-4" />
                                        </button>
                                        <button
                                            onClick={handleCancelEdit}
                                            className="p-1.5 text-gray-600 hover:bg-gray-50 rounded"
                                            title="Cancelar"
                                        >
                                            <X className="w-4 h-4" />
                                        </button>
                                    </>
                                ) : (
                                    <>
                                        <button
                                            onClick={() => handleEdit(template)}
                                            className="p-1.5 text-blue-600 hover:bg-blue-50 rounded"
                                            title="Editar"
                                        >
                                            <Edit2 className="w-4 h-4" />
                                        </button>
                                        {template.type === 'custom' && (
                                            <button
                                                onClick={() => handleDeleteTemplate(template.id!)}
                                                className="p-1.5 text-red-600 hover:bg-red-50 rounded"
                                                title="Eliminar"
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </button>
                                        )}
                                    </>
                                )}
                            </div>
                        </div>

                        {editingId === template.id ? (
                            <textarea
                                value={editContent}
                                onChange={(e) => setEditContent(e.target.value)}
                                className="w-full h-48 p-3 border rounded-lg font-mono text-sm resize-none"
                                placeholder="Escribe el contenido del mensaje..."
                            />
                        ) : (
                            <pre className="text-sm text-gray-600 bg-gray-50 p-3 rounded-lg overflow-x-auto whitespace-pre-wrap">
                                {template.content}
                            </pre>
                        )}
                    </div>
                ))}
            </div>

            {/* Variables Help */}
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                <h4 className="font-medium text-blue-800 mb-2">Variables Disponibles</h4>
                <div className="grid grid-cols-2 gap-2 text-sm text-blue-700">
                    <code>{'{{date}}'}</code> → Fecha de entrega
                    <code>{'{{signedBy}}'}</code> → Nombre del médico
                    <code>{'{{signedAt}}'}</code> → Hora de firma
                    <code>{'{{hospitalized}}'}</code> → Nº hospitalizados
                    <code>{'{{newAdmissions}}'}</code> → Nuevos ingresos
                    <code>{'{{discharges}}'}</code> → Altas
                    <code>{'{{handoffUrl}}'}</code> → Link a la entrega
                </div>
            </div>
        </div>
    );
};

export default MessageTemplatesEditor;

/**
 * Table Configuration Context
 * Manages table column widths with Firebase sync
 */

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import {
    TableConfig,
    TableColumnConfig,
    getDefaultConfig,
    DEFAULT_COLUMN_WIDTHS,

    saveTableConfig,
    subscribeToTableConfig,
    exportTableConfig,
    importTableConfig
} from '../services/storage/tableConfigService';

// ============================================================================
// Context Types
// ============================================================================

interface TableConfigContextType {
    config: TableConfig;
    isEditMode: boolean;
    isLoading: boolean;
    setEditMode: (enabled: boolean) => void;
    updateColumnWidth: (column: keyof TableColumnConfig, width: number) => void;
    updatePageMargin: (margin: number) => void;
    resetToDefaults: () => void;
    exportConfig: () => void;
    importConfig: (file: File) => Promise<void>;
}

// ============================================================================
// Context
// ============================================================================

const TableConfigContext = createContext<TableConfigContextType | undefined>(undefined);

// ============================================================================
// Provider
// ============================================================================

export const TableConfigProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [config, setConfig] = useState<TableConfig>(getDefaultConfig);
    const [isEditMode, setIsEditMode] = useState(false);
    const [isLoading, setIsLoading] = useState(true);

    // Debounce timer for saves
    const saveTimeoutRef = useRef<NodeJS.Timeout | null>(null);
    const localUpdateRef = useRef(false);

    // Load initial config and subscribe
    useEffect(() => {
        setIsLoading(true);

        // Subscribe to real-time updates
        const unsubscribe = subscribeToTableConfig((newConfig) => {
            // Skip if this update came from our local save
            if (!localUpdateRef.current) {
                setConfig(newConfig);
            }
            localUpdateRef.current = false;
            setIsLoading(false);
        });

        return () => unsubscribe();
    }, []);

    // Debounced save to Firebase
    const debouncedSave = useCallback((newConfig: TableConfig) => {
        if (saveTimeoutRef.current) {
            clearTimeout(saveTimeoutRef.current);
        }

        saveTimeoutRef.current = setTimeout(() => {
            localUpdateRef.current = true;
            saveTableConfig(newConfig).catch(console.error);
        }, 500);
    }, []);

    // Update single column width
    const updateColumnWidth = useCallback((column: keyof TableColumnConfig, width: number) => {
        setConfig(prev => {
            const newConfig = {
                ...prev,
                columns: {
                    ...prev.columns,
                    [column]: Math.max(24, Math.min(400, width)) // Clamp between 24-400px
                }
            };
            debouncedSave(newConfig);
            return newConfig;
        });
    }, [debouncedSave]);

    // Update page margin
    const updatePageMargin = useCallback((margin: number) => {
        setConfig(prev => {
            const newConfig = {
                ...prev,
                pageMargin: Math.max(0, Math.min(64, margin)) // Clamp between 0-64px
            };
            debouncedSave(newConfig);
            return newConfig;
        });
    }, [debouncedSave]);

    // Reset to default widths
    const resetToDefaults = useCallback(() => {
        const newConfig = getDefaultConfig();
        setConfig(newConfig);
        saveTableConfig(newConfig).catch(console.error);
    }, []);

    // Export current config
    const exportConfig = useCallback(() => {
        exportTableConfig(config);
    }, [config]);

    // Import config from file
    const handleImportConfig = useCallback(async (file: File) => {
        try {
            const importedConfig = await importTableConfig(file);
            setConfig(importedConfig);
            await saveTableConfig(importedConfig);
        } catch (error) {
            console.error('Failed to import config:', error);
            throw error;
        }
    }, []);

    // Toggle edit mode
    const setEditMode = useCallback((enabled: boolean) => {
        setIsEditMode(enabled);
    }, []);

    return (
        <TableConfigContext.Provider
            value={{
                config,
                isEditMode,
                isLoading,
                setEditMode,
                updateColumnWidth,
                updatePageMargin,
                resetToDefaults,
                exportConfig,
                importConfig: handleImportConfig
            }}
        >
            {children}
        </TableConfigContext.Provider>
    );
};

// ============================================================================
// Hook
// ============================================================================

export const useTableConfig = (): TableConfigContextType => {
    const context = useContext(TableConfigContext);
    if (!context) {
        throw new Error('useTableConfig must be used within a TableConfigProvider');
    }
    return context;
};

// Re-export types and utilities
export type { TableConfig, TableColumnConfig };
export { DEFAULT_COLUMN_WIDTHS };

import { initializeApp, type FirebaseOptions, type FirebaseApp } from 'firebase/app';
import { getAuth, connectAuthEmulator, setPersistence, browserLocalPersistence, type Auth } from 'firebase/auth';
import { initializeFirestore, connectFirestoreEmulator, type Firestore } from 'firebase/firestore';
import { getStorage, type FirebaseStorage } from 'firebase/storage';
import { getFunctions, connectFunctionsEmulator, type Functions } from 'firebase/functions';

const CACHED_CONFIG_KEY = 'hhr_firebase_config';

const decodeBase64 = (rawValue: string) => {
    const value = rawValue?.trim();
    if (!value) return '';

    const normalized = value
        .replace(/\s+/g, '')
        .replace(/-/g, '+')
        .replace(/_/g, '/')
        .padEnd(Math.ceil(value.length / 4) * 4, '=');

    try {
        if (typeof atob === 'function') {
            return atob(normalized);
        }

        return Buffer.from(normalized, 'base64').toString('utf-8');
    } catch (error) {
        console.warn('Firebase API key could not be decoded from base64:', error);
        return '';
    }
};

const mountConfigWarning = (message: string) => {
    console.warn(message);

    if (typeof document === 'undefined') return;
    const root = document.getElementById('root');
    if (!root) return;

    root.innerHTML = `
        <div style="min-height:100vh;display:flex;align-items:center;justify-content:center;background:#f8fafc;color:#0f172a;">
            <div style="max-width:520px;padding:24px;border-radius:12px;background:white;box-shadow:0 10px 40px rgba(15,23,42,0.12);font-family:Inter,sans-serif;">
                <h1 style="font-size:20px;font-weight:700;margin:0 0 12px 0;">Configuración de Firebase incompleta</h1>
                <p style="margin:0 0 8px 0;line-height:1.5;">La aplicación no puede iniciarse porque falta la clave API de Firebase.</p>
                <ol style="margin:0 0 12px 20px;line-height:1.5;">
                    <li>En Netlify, crea la variable <code>VITE_FIREBASE_API_KEY</code> (o <code>VITE_FIREBASE_API_KEY_B64</code> si prefieres base64) con tu API key de Firebase.</li>
                    <li>Vuelve a desplegar el sitio para que la configuración se aplique.</li>
                </ol>
                <p style="margin:0;color:#475569;font-size:14px;">Las claves se cargan en tiempo de ejecución desde una función serverless, por lo que no se incluyen en el bundle público.</p>
            </div>
        </div>
    `;
};

const saveCachedConfig = (config: FirebaseOptions) => {
    try {
        if (typeof localStorage === 'undefined') return;
        localStorage.setItem(CACHED_CONFIG_KEY, JSON.stringify(config));
    } catch (error) {
        console.warn('[FirebaseConfig] Failed to cache Firebase config:', error);
    }
};

const getCachedConfig = (): FirebaseOptions | null => {
    try {
        if (typeof localStorage === 'undefined') return null;
        const raw = localStorage.getItem(CACHED_CONFIG_KEY);
        if (!raw) return null;
        const parsed = JSON.parse(raw) as FirebaseOptions;
        return parsed.apiKey ? parsed : null;
    } catch (error) {
        console.warn('[FirebaseConfig] Failed to read cached Firebase config:', error);
        return null;
    }
};

const fetchRuntimeConfig = async (): Promise<FirebaseOptions> => {
    try {
        const configUrl = `/.netlify/functions/firebase-config?t=${Date.now()}&mode=recovery`;
        const response = await fetch(configUrl, {
            headers: { 'Cache-Control': 'no-cache' }
        });

        if (!response.ok) {
            throw new Error(`Runtime config request failed (${response.status})`);
        }

        const config = await response.json();
        return config satisfies FirebaseOptions;
    } catch (error) {
        throw error;
    }
};

const buildDevConfig = (): FirebaseOptions => {
    const encodedKey = import.meta.env.VITE_FIREBASE_API_KEY_B64 || '';
    const plainKey = import.meta.env.VITE_FIREBASE_API_KEY || '';
    const apiKey = encodedKey ? decodeBase64(encodedKey) : plainKey;

    return {
        apiKey,
        authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
        projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
        storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
        messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
        appId: import.meta.env.VITE_FIREBASE_APP_ID
    } satisfies FirebaseOptions;
};

const loadFirebaseConfig = async () => {
    if (import.meta.env.DEV) {
        return buildDevConfig();
    }

    const cached = getCachedConfig();

    try {
        const config = await fetchRuntimeConfig();
        saveCachedConfig(config);
        return config;
    } catch (error) {
        if (cached?.apiKey) {
            console.warn('[FirebaseConfig] Using cached Firebase config due to network error');
            return cached;
        }

        console.error('Failed to load Firebase config from Netlify function', error);
        mountConfigWarning('No se pudo cargar la configuración de Firebase desde Netlify. Verifica las variables en el panel de Netlify.');
        throw error;
    }
};

let app!: FirebaseApp;
let auth!: Auth;
let db!: Firestore;
let storage!: FirebaseStorage;
let functions!: Functions;

export const firebaseReady = (async () => {
    console.log('[FirebaseConfig] 🚀 Starting Firebase Ready sequence...');

    // Safety timeout for the entire initialization
    const timeout = new Promise((_, reject) => setTimeout(() => reject(new Error('Firebase initialization timed out')), 10000));

    try {
        const configPromise = (async () => {
            const config = await loadFirebaseConfig();
            console.log('[FirebaseConfig] 📁 Config loaded:', config.projectId);
            console.log('[FirebaseConfig] 🪣 Storage Bucket:', config.storageBucket || 'not set');

            if (!config.apiKey) {
                mountConfigWarning('Firebase API key is missing. Please configure it in Netlify.');
                throw new Error('Missing Firebase API key');
            }

            app = initializeApp(config);
            auth = getAuth(app);
            db = initializeFirestore(app, { ignoreUndefinedProperties: true });
            storage = getStorage(app);
            functions = getFunctions(app);

            setPersistence(auth, browserLocalPersistence).catch(err => {
                console.warn('[FirebaseConfig] Failed to set auth persistence:', err);
            });

            console.log('[FirebaseConfig] 🔥 Firebase initialized');

            const authEmulatorHost = import.meta.env.VITE_AUTH_EMULATOR_HOST;
            const firestoreEmulatorHost = import.meta.env.VITE_FIRESTORE_EMULATOR_HOST;

            if (import.meta.env.DEV && authEmulatorHost) {
                connectAuthEmulator(auth, authEmulatorHost);
            }

            if (import.meta.env.DEV && firestoreEmulatorHost) {
                const [host, port] = firestoreEmulatorHost.split(':');
                connectFirestoreEmulator(db, host, Number(port));
            }

            if (import.meta.env.DEV) {
                const functionsEmulatorHost = import.meta.env.VITE_FUNCTIONS_EMULATOR_HOST || 'localhost:5001';
                const [host, port] = functionsEmulatorHost.split(':');
                connectFunctionsEmulator(functions, host, Number(port));
            }

            return { app, auth, db, storage, functions };
        })();

        return await Promise.race([configPromise, timeout]) as any;
    } catch (err: any) {
        console.error('[FirebaseConfig] ❌ Critical initialization error:', err.message || err);
        // We throw here because without Firebase the app can't function properly
        // but it will be caught by anyone awaiting firebaseReady
        throw err;
    }
})();

export { app, auth, db, storage, functions, mountConfigWarning };
export default app;

import { useMemo } from 'react';
import { AuditLogEntry } from '../../types/audit';

export interface ClinicalData {
    bedHistory: { bedId: string, from: Date, to: Date | null, days: number }[];
    totalUpcDays: number;
    diagnosisHistory: { date: Date, pathology: string }[];
    devicesHistory: { date: Date, name: string, action: 'INSTALL' | 'REMOVE', details: string }[];
    firstAdmission?: string;
    lastDischarge?: string;
}

/**
 * Hook to process audit logs and extract clinical milestones, bed history, 
 * and invasive device usage for a specific patient.
 */
export const useClinicalData = (
    searchRut: string,
    chronologicalLogs: AuditLogEntry[],
    admissions: AuditLogEntry[],
    discharges: AuditLogEntry[]
): ClinicalData => {
    return useMemo(() => {
        const bedHistory: { bedId: string, from: Date, to: Date | null, days: number }[] = [];
        let totalUpcMs = 0;
        const diagnosisHistory: { date: Date, pathology: string }[] = [];
        const devicesHistory: { date: Date, name: string, action: 'INSTALL' | 'REMOVE', details: string }[] = [];

        if (!searchRut || chronologicalLogs.length === 0) {
            return {
                bedHistory: [],
                totalUpcDays: 0,
                diagnosisHistory: [],
                devicesHistory: [],
                firstAdmission: undefined,
                lastDischarge: undefined
            };
        }

        // Track current state during iteration
        let currentBed: string | null = null;
        let lastBedChange: Date | null = null;
        let isCurrentlyUpc = false;
        let lastUpcChange: Date | null = null;

        chronologicalLogs.forEach((log) => {
            const timestamp = new Date(log.timestamp);
            const details = log.details;

            // 1. Bed tracking
            const logBedId = details?.bedId;
            if (logBedId && logBedId !== currentBed) {
                if (currentBed && lastBedChange) {
                    const duration = timestamp.getTime() - lastBedChange.getTime();
                    bedHistory.push({
                        bedId: currentBed,
                        from: lastBedChange,
                        to: timestamp,
                        days: Math.max(1, Math.ceil(duration / (1000 * 60 * 60 * 24)))
                    });
                }
                currentBed = logBedId;
                lastBedChange = timestamp;
            }

            // 2. UPC tracking (clinicalFlags.isUPC or isUPC)
            const upcNew = details?.changes?.isUPC?.new ?? details?.changes?.["clinicalFlags.isUPC"]?.new ?? details?.isUPC;
            if (upcNew !== undefined && upcNew !== isCurrentlyUpc) {
                if (isCurrentlyUpc && lastUpcChange) {
                    totalUpcMs += timestamp.getTime() - lastUpcChange.getTime();
                }
                isCurrentlyUpc = !!upcNew;
                lastUpcChange = timestamp;
            }

            // 3. Diagnosis evolution
            const pathology = (details?.changes?.pathology?.new || details?.pathology) as string | undefined;
            if (pathology) {
                diagnosisHistory.push({ date: timestamp, pathology });
            }

            // 4. Invasive devices
            if (details?.changes?.deviceDetails) {
                Object.entries(details.changes.deviceDetails).forEach(([name, delta]: [string, any]) => {
                    devicesHistory.push({
                        date: timestamp,
                        name,
                        action: delta.new ? 'INSTALL' : 'REMOVE',
                        details: delta.new?.installationDate ? `Instalado el ${delta.new.installationDate}` : 'Retirado'
                    });
                });
            }
        });

        // Close last bed
        if (currentBed && lastBedChange) {
            const lastLog = discharges[discharges.length - 1];
            const end = (discharges.length > 0 && lastLog) ? new Date(lastLog.timestamp) : new Date();
            const duration = end.getTime() - (lastBedChange as Date).getTime();
            bedHistory.push({
                bedId: currentBed,
                from: lastBedChange,
                to: discharges.length > 0 ? end : null,
                days: Math.max(1, Math.ceil(duration / (1000 * 60 * 60 * 24)))
            });
        }

        // Close last UPC period
        if (isCurrentlyUpc && lastUpcChange) {
            const lastLog = discharges[discharges.length - 1];
            const end = (discharges.length > 0 && lastLog) ? new Date(lastLog.timestamp) : new Date();
            totalUpcMs += end.getTime() - (lastUpcChange as Date).getTime();
        }

        return {
            bedHistory: bedHistory.reverse(),
            totalUpcDays: Math.ceil(totalUpcMs / (1000 * 60 * 60 * 24)),
            diagnosisHistory: diagnosisHistory.reverse(),
            devicesHistory: devicesHistory.reverse(),
            firstAdmission: admissions[0]?.timestamp,
            lastDischarge: discharges[discharges.length - 1]?.timestamp
        };
    }, [searchRut, chronologicalLogs, admissions, discharges]);
};

/**
 * useAudit Hook
 * Provides audit logging functions with user context.
 * Must be used within a component that has access to authenticated user.
 */

import React, { useCallback } from 'react';
import { logAuditEvent, getAuditLogs, AUDIT_ACTION_LABELS } from '../services/admin/auditService';
import { AuditAction, AuditLogEntry } from '../types/audit';

interface UseAuditReturn {
    // Logging functions
    logPatientAdmission: (bedId: string, patientName: string, rut: string, recordDate: string) => void;
    logPatientDischarge: (bedId: string, patientName: string, rut: string, status: string, recordDate: string) => void;
    logPatientTransfer: (bedId: string, patientName: string, rut: string, destination: string, recordDate: string) => void;
    logPatientCleared: (bedId: string, patientName: string, rut: string, recordDate: string) => void;
    logDailyRecordDeleted: (date: string) => void;
    logDailyRecordCreated: (date: string, copiedFrom?: string) => void;
    logPatientView: (bedId: string, patientName: string, rut: string, recordDate: string, authors?: string) => void;
    // Generic logger
    logEvent: (action: AuditAction, entityType: AuditLogEntry['entityType'], entityId: string, details: Record<string, unknown>, patientRut?: string, recordDate?: string, authors?: string) => void;
    // Smart logger (debounced)
    logDebouncedEvent: (action: AuditAction, entityType: AuditLogEntry['entityType'], entityId: string, details: Record<string, unknown>, patientRut?: string, recordDate?: string, authors?: string) => void;
    // Fetching
    fetchLogs: (limit?: number) => Promise<AuditLogEntry[]>;
    // Labels
    getActionLabel: (action: AuditAction) => string;
}

export const useAudit = (userId: string): UseAuditReturn => {
    // Store timers for debounced events (key: action-entityId)
    // We use 'any' for timer to avoid NodeJS vs Browser type conflicts
    const timersRef = React.useRef<Record<string, {
        timer: number,
        details: Record<string, unknown>,
        rut?: string,
        date?: string,
        authors?: string
    }>>({});

    const logEvent = useCallback((
        action: AuditAction,
        entityType: AuditLogEntry['entityType'],
        entityId: string,
        details: Record<string, unknown>,
        patientRut?: string,
        recordDate?: string,
        authors?: string
    ) => {
        // Fire and forget - don't await
        logAuditEvent(userId, action, entityType, entityId, details, patientRut, recordDate, authors);
    }, [userId]);

    // Smart logger (debounced with merging)
    const logDebouncedEvent = useCallback((
        action: AuditAction,
        entityType: AuditLogEntry['entityType'],
        entityId: string,
        details: Record<string, unknown>,
        patientRut?: string,
        recordDate?: string,
        authors?: string,
        waitMs: number = 5 * 60 * 1000 // Default 5 mins
    ) => {
        const key = `${action}-${entityId}`;

        // Get existing pending entry
        const pending = timersRef.current[key];

        // Merge changes if they exist
        let mergedDetails = { ...details };
        if (pending && pending.details && details.changes) {
            const oldChanges = (pending.details.changes || {}) as Record<string, { old?: unknown; new?: unknown } | unknown>;
            const newChanges = (details.changes || {}) as Record<string, { old?: unknown; new?: unknown } | unknown>;

            // Merge logic: Preserve the FIRST 'old' value in the chain
            // but take the LAST 'new' value.
            const mergedChanges: Record<string, unknown> = { ...oldChanges };

            Object.keys(newChanges).forEach(field => {
                const oldVal = mergedChanges[field] as Record<string, unknown> | undefined;
                const newVal = newChanges[field] as Record<string, unknown> | undefined;

                if (oldVal && typeof oldVal === 'object' && 'old' in oldVal) {
                    // Field already exists in pending log, keep its 'old' value
                    mergedChanges[field] = {
                        old: oldVal.old,
                        new: newVal && typeof newVal === 'object' && 'new' in newVal ? (newVal as any).new : newChanges[field]
                    };
                } else {
                    // New field being modified
                    mergedChanges[field] = newChanges[field];
                }
            });

            mergedDetails = {
                ...pending.details,
                ...details,
                changes: mergedChanges
            };
        }

        // Clear existing timer (explicitly using window for browser environment)
        if (pending) {
            window.clearTimeout(pending.timer);
        }

        // Set a new timer
        const timer = window.setTimeout(() => {
            const entry = timersRef.current[key];
            if (entry) {
                logEvent(action, entityType, entityId, entry.details, entry.rut, entry.date, entry.authors);
                delete timersRef.current[key];
            }
        }, waitMs);

        // Store merged details and timer
        timersRef.current[key] = {
            timer,
            details: mergedDetails,
            rut: patientRut,
            date: recordDate,
            authors
        };
    }, [logEvent]);

    const logPatientAdmission = useCallback((bedId: string, patientName: string, rut: string, recordDate: string) => {
        logEvent('PATIENT_ADMITTED', 'patient', bedId, { patientName, bedId }, rut, recordDate);
    }, [logEvent]);

    const logPatientDischarge = useCallback((bedId: string, patientName: string, rut: string, status: string, recordDate: string) => {
        logEvent('PATIENT_DISCHARGED', 'discharge', bedId, { patientName, status, bedId }, rut, recordDate);
    }, [logEvent]);

    const logPatientTransfer = useCallback((bedId: string, patientName: string, rut: string, destination: string, recordDate: string) => {
        logEvent('PATIENT_TRANSFERRED', 'transfer', bedId, { patientName, destination, bedId }, rut, recordDate);
    }, [logEvent]);

    const logPatientCleared = useCallback((bedId: string, patientName: string, rut: string, recordDate: string) => {
        logEvent('PATIENT_CLEARED', 'patient', bedId, { patientName, bedId }, rut, recordDate);
    }, [logEvent]);

    const logDailyRecordDeleted = useCallback((date: string) => {
        logEvent('DAILY_RECORD_DELETED', 'dailyRecord', date, { date }, undefined, date);
    }, [logEvent]);

    const logDailyRecordCreated = useCallback((date: string, copiedFrom?: string) => {
        logEvent('DAILY_RECORD_CREATED', 'dailyRecord', date, { date, copiedFrom }, undefined, date);
    }, [logEvent]);

    const logPatientView = useCallback((bedId: string, patientName: string, rut: string, recordDate: string, authors?: string) => {
        logEvent('PATIENT_VIEWED', 'patient', bedId, { patientName, bedId }, rut, recordDate, authors);
    }, [logEvent]);

    const fetchLogs = useCallback(async (limit: number = 100): Promise<AuditLogEntry[]> => {
        return getAuditLogs(limit);
    }, []);

    const getActionLabel = useCallback((action: AuditAction): string => {
        return AUDIT_ACTION_LABELS[action] || action;
    }, []);

    return {
        logPatientAdmission,
        logPatientDischarge,
        logPatientTransfer,
        logPatientCleared,
        logDailyRecordDeleted,
        logDailyRecordCreated,
        logPatientView,
        logEvent,
        logDebouncedEvent,
        fetchLogs,
        getActionLabel
    };
};

/**
 * useBackupFilesQuery Hook
 * TanStack Query wrapper for backup file listing.
 * Natively resolves race conditions when navigating between folders.
 */

import { useQuery } from '@tanstack/react-query';
import {
    listYears as listHandoffYears,
    listMonths as listHandoffMonths,
    listFilesInMonth as listHandoffFiles
} from '../services/backup/pdfStorageService';
import {
    listCensusYears,
    listCensusMonths,
    listCensusFilesInMonth
} from '../services/backup/censusStorageService';
import {
    listCudyrYears,
    listCudyrMonths,
    listCudyrFilesInMonth
} from '../services/backup/cudyrStorageService';
import { MONTH_NAMES } from '../services/backup/baseStorageService';

export type BackupItemType = 'folder' | 'file';

export interface BackupItem {
    type: BackupItemType;
    data: any;
}

const monthNameToNumber = (name: string): string => {
    const index = MONTH_NAMES.indexOf(name);
    return String(index + 1).padStart(2, '0');
};

export const useBackupFilesQuery = (backupType: string, path: string[]) => {
    return useQuery({
        queryKey: ['backups', backupType, ...path],
        queryFn: async (): Promise<BackupItem[]> => {
            // console.debug(`[useBackupFilesQuery] 📂 Fetching ${backupType} backups for path: /${path.join('/')}`);

            // 1. Determine service based on type
            const service = {
                listYears: backupType === 'handoff' ? listHandoffYears : (backupType === 'census' ? listCensusYears : listCudyrYears),
                listMonths: backupType === 'handoff' ? listHandoffMonths : (backupType === 'census' ? listCensusMonths : listCudyrMonths),
                listFilesInMonth: backupType === 'handoff' ? listHandoffFiles : (backupType === 'census' ? listCensusFilesInMonth : listCudyrFilesInMonth),
            };

            if (path.length === 0) {
                // Root: List years
                // console.debug('[useBackupFilesQuery] 📅 Fetching years...');
                const years = await service.listYears();
                // console.debug(`[useBackupFilesQuery] ✅ Found years: ${years.join(', ')}`);
                return years.map(year => ({
                    type: 'folder',
                    data: { name: year, type: 'year' }
                }));
            } else if (path.length === 1) {
                // Year: List months
                const year = path[0];
                // console.debug(`[useBackupFilesQuery] 📅 Fetching months for year: ${year}`);
                const months = await service.listMonths(year);
                // console.debug(`[useBackupFilesQuery] ✅ Found months: ${months.length}`);
                return months.map(month => ({
                    type: 'folder',
                    data: { name: month.name, number: month.number, type: 'month' }
                }));
            } else if (path.length === 2) {
                // Month: List files
                const year = path[0];
                const monthName = path[1];
                const monthNumber = monthNameToNumber(monthName);

                // console.debug(`[useBackupFilesQuery] 📄 Fetching files for ${year}/${monthNumber} (${monthName})`);
                const files = await service.listFilesInMonth(year, monthNumber);
                // console.debug(`[useBackupFilesQuery] ✅ Found files: ${files.length}`);

                return files.map(file => ({
                    type: 'file',
                    data: file
                }));
            }

            return [];
        },
        staleTime: 1000 * 60 * 5, // 5 minutes
    });
};

import { useCallback } from 'react';
import { DailyRecord, PatientData, CudyrScore, PatientFieldValue, DailyRecordPatch, DailyRecordPatchPath } from '../types';
import { useAuditContext } from '../context/AuditContext';
import { getAttributedAuthors } from '../services/admin/attributionService';
import { usePatientValidation } from './usePatientValidation';
import { useBedOperations } from './useBedOperations';
import { useClinicalCrib } from './useClinicalCrib';
import { logPatientAdmission } from '../services/admin/auditService';


/**
 * Interface defining the actions available for bed management.
 */
export interface BedManagementActions {
    /**
     * Updates a single field for a patient in a specific bed.
     * Includes validation and audit logging for admissions.
     */
    updatePatient: (bedId: string, field: keyof PatientData, value: PatientFieldValue) => void;

    /**
     * Updates multiple patient fields atomically.
     */
    updatePatientMultiple: (bedId: string, fields: Partial<PatientData>) => void;

    /**
     * Updates a specific field in the CUDYR score for a patient.
     */
    updateCudyr: (bedId: string, field: keyof CudyrScore, value: number) => void;

    /**
     * Manages clinical crib operations (create, remove, or update fields).
     */
    updateClinicalCrib: (bedId: string, field: keyof PatientData | 'create' | 'remove', value?: PatientFieldValue) => void;

    /**
     * Updates multiple clinical crib fields atomically.
     */
    updateClinicalCribMultiple: (bedId: string, fields: Partial<PatientData>) => void;

    /**
     * Updates a specific field in the CUDYR score for a clinical crib.
     */
    updateClinicalCribCudyr: (bedId: string, field: keyof CudyrScore, value: number) => void;

    /**
     * Clears patient data from a bed (Discharge/Cleanup).
     */
    clearPatient: (bedId: string) => void;

    /**
     * Clears all beds in the current record.
     */
    clearAllBeds: () => void;

    /**
     * Moves or copies a patient from one bed to another.
     */
    moveOrCopyPatient: (type: 'move' | 'copy', sourceBedId: string, targetBedId: string) => void;

    /**
     * Toggles the blocked status of a bed with an optional reason.
     */
    toggleBlockBed: (bedId: string, reason?: string) => void;
    updateBlockedReason: (bedId: string, reason: string) => void;

    /**
     * Toggles an extra bed visibility.
     */
    toggleExtraBed: (bedId: string) => void;
}

// ============================================================================
// Hook Implementation
// ============================================================================

/**
 * useBedManagement Hook
 * 
 * Orchestrates all bed-related operations including patient data updates,
 * CUDYR scoring, and physical bed management (blocking, moving).
 * 
 * @param record - The current DailyRecord (Source of truth for the UI)
 * @param saveAndUpdate - Function to save the entire record (Full write)
 * @param patchRecord - Function to perform partial updates (Atomic writes via dot-notation)
 *                      Uses Firestore updateDoc behavior: only specified fields are changed,
 *                      preventing data loss from concurrent edits on different beds.
 * @returns An object containing all bed management actions
 */
export const useBedManagement = (
    record: DailyRecord | null,
    saveAndUpdate: (updatedRecord: DailyRecord) => void,
    patchRecord: (partial: DailyRecordPatch) => Promise<void>
): BedManagementActions => {
    const { logDebouncedEvent, userId } = useAuditContext();

    // ========================================================================
    // Compose Specialized Hooks
    // ========================================================================

    const validation = usePatientValidation();
    const bedOperations = useBedOperations(record, patchRecord);
    const cribActions = useClinicalCrib(record, saveAndUpdate, patchRecord);

    // ========================================================================
    // Patient Updates
    // ========================================================================

    const updatePatient = useCallback((
        bedId: string,
        field: keyof PatientData,
        value: PatientFieldValue
    ) => {
        if (!record) return;

        // Validate and process the field value
        const result = validation.processFieldValue(field, value);

        if (!result.valid) {
            console.warn(`Validation failed for ${field}:`, result.error);
            return;
        }

        const processedValue = result.value;
        const oldPatient = record.beds[bedId];
        const oldValue = oldPatient[field];

        // Audit Logging for patient admission/modification
        if (field === 'patientName') {
            const oldName = oldPatient.patientName;
            const newName = processedValue as string;
            // Admission: Empty -> Name
            if (!oldName && newName) {
                logPatientAdmission(bedId, newName, oldPatient.rut, oldPatient.pathology, record.date);
            } else if (oldName && newName && oldName !== newName) {
                // Name modification
                logDebouncedEvent(
                    'PATIENT_MODIFIED',
                    'patient',
                    bedId,
                    {
                        patientName: newName,
                        changes: { [field]: { old: oldName, new: newName } }
                    },
                    oldPatient.rut,
                    record.date
                );
            }
        } else if (field === 'deviceDetails') {
            // Specialized auditing for invasive devices
            const oldDevices = (oldPatient.deviceDetails || {}) as Record<string, any>;
            const newDevices = (processedValue || {}) as Record<string, any>;

            // Detect which device changed
            const allKeys = Array.from(new Set([...Object.keys(oldDevices), ...Object.keys(newDevices)]));
            const deviceChanges: Record<string, any> = {};

            allKeys.forEach(device => {
                const oldD = oldDevices[device];
                const newD = newDevices[device];
                if (JSON.stringify(oldD) !== JSON.stringify(newD)) {
                    deviceChanges[device] = { old: oldD || 'N/A', new: newD || 'Eliminado' };
                }
            });

            if (Object.keys(deviceChanges).length > 0) {
                logDebouncedEvent(
                    'PATIENT_MODIFIED',
                    'patient',
                    bedId,
                    {
                        patientName: oldPatient.patientName,
                        changes: { deviceDetails: deviceChanges }
                    },
                    oldPatient.rut,
                    record.date
                );
            }
        } else if (oldValue !== processedValue) {
            // Critical fields logging
            const criticalFields: (keyof PatientData)[] = [
                'pathology', 'age', 'specialty', 'status', 'biologicalSex',
                'insurance', 'admissionOrigin', 'origin', 'admissionDate'
            ];

            if (criticalFields.includes(field)) {
                logDebouncedEvent(
                    'PATIENT_MODIFIED',
                    'patient',
                    bedId,
                    {
                        patientName: oldPatient.patientName,
                        changes: { [field]: { old: oldValue, new: processedValue } }
                    },
                    oldPatient.rut,
                    record.date
                );
            }
        }

        // Send an atomic patch to the database.
        // We use dot-notation (e.g., "beds.bed-1.patientName") so Firestore 
        // only updates that specific leaf node. This is critical for concurrency
        // as other users might be updating "beds.bed-2" at the same time.
        patchRecord({
            [`beds.${bedId}.${field}`]: processedValue
        });
    }, [record, validation, patchRecord, logDebouncedEvent]);

    /**
     * Update multiple patient fields atomically
     */
    const updatePatientMultiple = useCallback((
        bedId: string,
        fields: Partial<PatientData>
    ) => {
        if (!record) return;

        const patches: Record<string, any> = {};

        for (const [key, value] of Object.entries(fields)) {
            const field = key as keyof PatientData;
            const result = validation.processFieldValue(field, value as PatientFieldValue);

            if (result.valid) {
                patches[`beds.${bedId}.${key}` as DailyRecordPatchPath] = result.value;
            }
        }

        if (Object.keys(patches).length > 0) {
            patchRecord(patches);
        }
    }, [record, validation, patchRecord]);

    // ========================================================================
    // CUDYR Updates
    // ========================================================================

    const updateCudyr = useCallback((
        bedId: string,
        field: keyof CudyrScore,
        value: number
    ) => {
        if (!record) return;

        // Audit Log (Smart/Debounced)
        if (record.beds[bedId].patientName) {
            // Attribution logic for shared accounts (MINSAL requirement)
            const authors = getAttributedAuthors(userId, record);

            logDebouncedEvent(
                'CUDYR_MODIFIED',
                'dailyRecord',
                record.date,
                {
                    patientName: record.beds[bedId].patientName,
                    bedId,
                    field,
                    value,
                    oldValue: record.beds[bedId].cudyr?.[field] || 0
                },
                record.beds[bedId].rut,
                record.date,
                authors
            );
        }

        patchRecord({
            [`beds.${bedId}.cudyr.${field}`]: value
        });
    }, [record, patchRecord, logDebouncedEvent, userId]);

    // ========================================================================
    // Clinical Crib Wrapper (maintains backwards compatibility)
    // ========================================================================

    const updateClinicalCrib = useCallback((
        bedId: string,
        field: keyof PatientData | 'create' | 'remove',
        value?: PatientFieldValue
    ) => {
        if (field === 'create') {
            cribActions.createCrib(bedId);
        } else if (field === 'remove') {
            cribActions.removeCrib(bedId);
        } else {
            cribActions.updateCribField(bedId, field, value);
        }
    }, [cribActions]);

    const updateClinicalCribMultiple = useCallback((
        bedId: string,
        fields: Partial<PatientData>
    ) => {
        cribActions.updateCribMultiple(bedId, fields);
    }, [cribActions]);

    /**
     * Updates CUDYR score for a clinical crib.
     */
    const updateClinicalCribCudyr = useCallback((
        bedId: string,
        field: keyof CudyrScore,
        value: number
    ) => {
        if (!record) return;

        const crib = record.beds[bedId]?.clinicalCrib;
        if (crib?.patientName) {
            const authors = getAttributedAuthors(userId, record);
            logDebouncedEvent(
                'CUDYR_MODIFIED',
                'dailyRecord',
                record.date,
                {
                    patientName: crib.patientName,
                    bedId: `${bedId}-crib`,
                    field,
                    value,
                    oldValue: crib.cudyr?.[field] || 0
                },
                crib.rut,
                record.date,
                authors
            );
        }

        patchRecord({
            [`beds.${bedId}.clinicalCrib.cudyr.${field}`]: value
        });
    }, [record, patchRecord, logDebouncedEvent, userId]);

    // ========================================================================
    // Return API (composing all hooks)
    // ========================================================================

    return {
        // Patient Updates
        updatePatient,
        updatePatientMultiple,
        updateCudyr,

        // Clinical Crib (delegated)
        updateClinicalCrib,
        updateClinicalCribMultiple,
        updateClinicalCribCudyr,

        // Bed Operations (delegated)
        clearPatient: bedOperations.clearPatient,
        clearAllBeds: bedOperations.clearAllBeds,
        moveOrCopyPatient: bedOperations.moveOrCopyPatient,
        toggleBlockBed: bedOperations.toggleBlockBed,
        updateBlockedReason: bedOperations.updateBlockedReason,
        toggleExtraBed: bedOperations.toggleExtraBed
    };
};

/**
 * useClinicalCrib Hook
 * Manages clinical crib (nested patient) operations.
 * Extracted from useBedManagement for better separation of concerns.
 */

import { useCallback } from 'react';
import { DailyRecord, PatientData, PatientFieldValue } from '../types';
import { createEmptyPatient } from '../services/factories/patientFactory';

export interface ClinicalCribActions {
    createCrib: (bedId: string) => void;
    removeCrib: (bedId: string) => void;
    updateCribField: (bedId: string, field: keyof PatientData, value: PatientFieldValue) => void;
    updateCribMultiple: (bedId: string, updates: Partial<PatientData>) => void;
}

export const useClinicalCrib = (
    record: DailyRecord | null,
    saveAndUpdate: (updatedRecord: DailyRecord) => void,
    patchRecord: (partial: Record<string, any>) => Promise<void>
): ClinicalCribActions => {

    /**
     * Create a new clinical crib for a patient bed
     */
    const createCrib = useCallback((bedId: string) => {
        if (!record) return;

        const parentPatient = record.beds[bedId];

        // Validation: Cannot add crib to empty bed
        if (!parentPatient.patientName) {
            console.warn(`Cannot add clinical crib to empty bed ${bedId}`);
            return;
        }

        const newCrib = createEmptyPatient(bedId);
        newCrib.bedMode = 'Cuna';

        patchRecord({
            [`beds.${bedId}.clinicalCrib`]: newCrib,
            [`beds.${bedId}.hasCompanionCrib`]: false
        });
    }, [record, patchRecord]);

    /**
     * Remove clinical crib from a patient bed
     */
    const removeCrib = useCallback((bedId: string) => {
        if (!record) return;

        patchRecord({
            [`beds.${bedId}.clinicalCrib`]: null
        });
    }, [record, patchRecord]);

    /**
     * Update a field on the clinical crib
     */
    const updateCribField = useCallback((
        bedId: string,
        field: keyof PatientData,
        value: PatientFieldValue
    ) => {
        if (!record) return;

        // Validation: Admission date cannot be in the future
        if (field === 'admissionDate' && typeof value === 'string') {
            const selectedDate = new Date(value);
            const today = new Date();
            today.setHours(0, 0, 0, 0);
            if (selectedDate > today) {
                console.warn("Cannot set admission date to future");
                return;
            }
        }

        const parentPatient = record.beds[bedId];
        if (!parentPatient.clinicalCrib) return;

        patchRecord({
            [`beds.${bedId}.clinicalCrib.${field}`]: value
        });
    }, [record, patchRecord]);

    /**
     * Update multiple clinical crib fields atomically
     */
    const updateCribMultiple = useCallback((bedId: string, updates: Partial<PatientData>) => {
        if (!record) return;

        const parentPatient = record.beds[bedId];
        if (!parentPatient.clinicalCrib) return;

        if (updates.admissionDate) {
            const selectedDate = new Date(updates.admissionDate as string);
            const today = new Date();
            today.setHours(0, 0, 0, 0);
            if (selectedDate > today) {
                console.warn("Cannot set admission date to future");
                delete updates.admissionDate;
            }
        }

        const patches: Record<string, any> = {};
        Object.entries(updates).forEach(([key, value]) => {
            patches[`beds.${bedId}.clinicalCrib.${key}`] = value;
        });

        patchRecord(patches);

    }, [record, patchRecord]);

    return {
        createCrib,
        removeCrib,
        updateCribField,
        updateCribMultiple
    };
};

/**
 * DailyRecord Context Types
 * Type definitions for the DailyRecord context API.
 * Separated for clarity and reusability.
 */

import { DailyRecord, PatientData, CudyrScore, TransferData, PatientFieldValue, CMAData, DailyRecordPatch } from '../types';
export type { DailyRecordPatch };

