 * and won't trigger re-renders when data changes.
 */
export interface DailyRecordActionsContextType {
    // Day Management
    createDay: (copyFromPrevious: boolean, specificDate?: string) => void;
    generateDemo: () => void;
    resetDay: () => Promise<void>;
