    // Validation helpers
    validateRecordSchema: (record: DailyRecord) => { isValid: boolean; errors: any[] };
    canMovePatient: (sourceBedId: string, targetBedId: string, record: DailyRecord | null) => { canMove: boolean; reason?: string };
