/**
 * useExamRequest Hook
 * Manages state and logic for the laboratory exam request form.
 */

import { useState, useCallback, useEffect } from 'react';
import { PatientData } from '@/types';

interface UseExamRequestParams {
    patient: PatientData;
    isOpen: boolean;
}

interface UseExamRequestReturn {
    // State
    selectedExams: Set<string>;
    procedencia: string;
    prevision: string;

    // Setters
    setProcedencia: (value: string) => void;
    setPrevision: (value: string) => void;

    // Actions
    toggleExam: (examKey: string) => void;
    handlePrint: () => void;
    getSelectedCount: () => number;
}

export const useExamRequest = ({ patient, isOpen }: UseExamRequestParams): UseExamRequestReturn => {
    const [selectedExams, setSelectedExams] = useState<Set<string>>(new Set());
    const [procedencia, setProcedencia] = useState('Hospitalización');
    const [prevision, setPrevision] = useState(patient.insurance || 'FONASA');

    // Reset state when opening
    useEffect(() => {
        if (isOpen) {
            setSelectedExams(new Set());
            setPrevision(patient.insurance || 'FONASA');
        }
    }, [isOpen, patient]);

    const toggleExam = useCallback((examKey: string) => {
        setSelectedExams(prev => {
            const next = new Set(prev);
            if (next.has(examKey)) next.delete(examKey);
            else next.add(examKey);
            return next;
        });
    }, []);

    const handlePrint = useCallback(() => {
        const originalTitle = document.title;
        const modalTitleElement = document.getElementById('modal-title-text');
        const originalModalTitle = modalTitleElement?.innerText;

        // 1. Clear browser title
        document.title = ' ';

        // 2. Clear modal title in DOM directly
        if (modalTitleElement) {
            modalTitleElement.innerText = '';
        }

        setTimeout(() => {
            window.print();

            // 3. Restore everything
            setTimeout(() => {
                document.title = originalTitle;
                if (modalTitleElement && originalModalTitle) {
                    modalTitleElement.innerText = originalModalTitle;
                }
            }, 1000);
        }, 150);
    }, []);

    const getSelectedCount = useCallback(() => selectedExams.size, [selectedExams]);

    return {
        selectedExams,
        procedencia,
        prevision,
        setProcedencia,
        setPrevision,
        toggleExam,
        handlePrint,
        getSelectedCount
    };
};

/**
 * useExcelParser Hook
 * 
 * Extracted from SharedCensusView.tsx to handle Excel file parsing with ExcelJS.
 * Supports multiple sheets, merged cells (colSpan/rowSpan), and rich text values.
 * 
 * This hook is reusable for any Excel viewing functionality in the application.
 */

import { useState, useCallback, useRef, useEffect } from 'react';
import { createWorkbook } from '../services/exporters/excelUtils';

// ============================================================================
// Types
// ============================================================================

interface ExcelRichText {
    text: string;
}

interface ExcelFormula {
    formula?: string;
    result?: unknown;
}

interface ExcelErrorValue {
    error: string;
}

export interface ParsedCell {
    value: string | number | Date | null | boolean;
    colSpan: number;
    rowSpan: number;
    hidden: boolean;
}

export interface UseExcelParserReturn {
    // Data
    workbookData: Record<string, ParsedCell[][]>;
    sheetNames: string[];
    activeSheet: string;
    setActiveSheet: (sheet: string) => void;

    // Loading state
    isParsing: boolean;
    parseError: string | null;

    // Actions
    parseFromUrl: (url: string) => Promise<void>;
    parseFromBlob: (blob: Blob) => Promise<void>;
    reset: () => void;
}

// ============================================================================
// Hook Implementation
// ============================================================================

export function useExcelParser(): UseExcelParserReturn {
    const [workbookData, setWorkbookData] = useState<Record<string, ParsedCell[][]>>({});
    const [sheetNames, setSheetNames] = useState<string[]>([]);
    const [activeSheet, setActiveSheet] = useState<string>('');
    const [isParsing, setIsParsing] = useState(false);
    const [parseError, setParseError] = useState<string | null>(null);

    // Check if component is mounted to avoid state updates after unmount
    const abortControllerRef = useRef<AbortController | null>(null);

    /**
     * Reset all parser state and abort pending requests
     */
    const reset = useCallback(() => {
        if (abortControllerRef.current) {
            abortControllerRef.current.abort();
            abortControllerRef.current = null;
        }
        setWorkbookData({});
        setSheetNames([]);
        setActiveSheet('');
        setParseError(null);
        setIsParsing(false);
    }, []);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            if (abortControllerRef.current) {
                abortControllerRef.current.abort();
            }
        };
    }, []);

    /**
     * Core parsing logic - processes a Blob into structured cell data
     * Note: This function is not cancellable once plain blob is received, 
     * but we check signal before setting state.
     */
    const parseFromBlob = useCallback(async (blob: Blob) => {
        setIsParsing(true);
        setParseError(null);
        setWorkbookData({});
        setSheetNames([]);
        setActiveSheet('');

        try {
            const workbook = await createWorkbook();
            const buffer = await blob.arrayBuffer();
            await workbook.xlsx.load(buffer);

            const allSheetsData: Record<string, ParsedCell[][]> = {};
            const names: string[] = [];

            workbook.eachSheet((worksheet) => {
                const sheetName = worksheet.name;
                names.push(sheetName);

                const grid: ParsedCell[][] = [];
                const rowsCount = worksheet.rowCount;
                const colsCount = worksheet.columnCount;
                const hiddenCells = new Set<string>();

                for (let r = 1; r <= rowsCount; r++) {
                    const rowGrid: ParsedCell[] = [];
                    const row = worksheet.getRow(r);

                    for (let c = 1; c <= colsCount; c++) {
                        const cellRef = `${r},${c}`;

                        // Skip cells that are part of a merge (not the master cell)
                        if (hiddenCells.has(cellRef)) {
                            rowGrid.push({ value: null, colSpan: 1, rowSpan: 1, hidden: true });
                            continue;
                        }

                        const cell = row.getCell(c);
                        let val = cell.value;

                        // Extract actual value from complex cell types
                        if (val && typeof val === 'object') {
                            if ('richText' in val && Array.isArray((val as { richText: unknown }).richText)) {
                                // Rich text - concatenate all text parts
                                val = ((val as { richText: ExcelRichText[] }).richText).map((rt) => rt.text).join('');
                            } else if ('formula' in val || 'result' in val) {
                                // Formula cell - get the result
                                const formulaRes = (val as ExcelFormula).result;
                                // Default to 0 if result is missing
                                val = (formulaRes === undefined || formulaRes === null) ? 0 : formulaRes as string | number | Date;
                            } else if ('text' in val) {
                                // Hyperlink or similar
                                val = (val as { text: string }).text;
                            }

                            // Handle if the extracted result is STILL an object
                            if (val && typeof val === 'object') {
                                if ('error' in val) {
                                    val = (val as ExcelErrorValue).error;
                                } else if (val instanceof Date) {
                                    // Keep as Date object
                                } else {
                                    // Fallback for unknown objects
                                    val = '';
                                }
                            }
                        }

                        // Ensure val is of allowed type or cast to string
                        let finalVal: string | number | Date | null | boolean = null;
                        if (val === null || val === undefined) finalVal = null;
                        else if (typeof val === 'string' || typeof val === 'number' || typeof val === 'boolean' || val instanceof Date) {
                            finalVal = val;
                        } else {
                            finalVal = String(val);
                        }

                        let colSpan = 1;
                        let rowSpan = 1;

                        // Handle merged cells
                        if (cell.isMerged) {
                            const master = cell.master;

                            // If this is not the master cell, mark as hidden
                            if (master.address !== cell.address) {
                                rowGrid.push({ value: null, colSpan: 1, rowSpan: 1, hidden: true });
                                continue;
                            }

                            // Get merge range from worksheet internal data
                            const range = (worksheet as any)._merges?.[cell.address];
                            if (range) {
                                colSpan = range.right - range.left + 1;
                                rowSpan = range.bottom - range.top + 1;

                                // Mark all cells in the merge as hidden (except master)
                                for (let mr = range.top; mr <= range.bottom; mr++) {
                                    for (let mc = range.left; mc <= range.right; mc++) {
                                        if (mr === r && mc === c) continue;
                                        hiddenCells.add(`${mr},${mc}`);
                                    }
                                }
                            }
                        }

                        rowGrid.push({ value: finalVal, colSpan, rowSpan, hidden: false });
                    }
                    grid.push(rowGrid);
                }
                allSheetsData[sheetName] = grid;
            });

            setWorkbookData(allSheetsData);
            setSheetNames(names);
            if (names.length > 0) {
                setActiveSheet(names[0]);
            }
        } catch (err) {
            console.error('[useExcelParser] Error parsing excel:', err);
            setParseError('No se pudo cargar el archivo. Intenta descargarlo.');
        } finally {
            setIsParsing(false);
        }
    }, []);

    /**
     * Fetch and parse from a URL
     */
    const parseFromUrl = useCallback(async (url: string) => {
        // Abort previous request if any
        if (abortControllerRef.current) {
            abortControllerRef.current.abort();
        }

        const controller = new AbortController();
        abortControllerRef.current = controller;

        setIsParsing(true);
        setParseError(null);

        try {
            const response = await fetch(url, { signal: controller.signal });
            if (!response.ok) throw new Error(`Failed to fetch file: ${response.status}`);

            const blob = await response.blob();

            // Check if aborted during blob reading
            if (controller.signal.aborted) return;

            await parseFromBlob(blob);
        } catch (err: any) {
            if (err.name === 'AbortError') {
                console.warn('[useExcelParser] Fetch aborted');
                return;
            }
            console.error('[useExcelParser] Error fetching file:', err);
            setParseError('No se pudo descargar el archivo para visualización.');
            setIsParsing(false);
        } finally {
            // Only clear loading if this is the active request
            if (abortControllerRef.current === controller) {
                abortControllerRef.current = null;
                // Note: parseFromBlob handles its own setIsParsing(false), 
                // but if we errored/aborted before calling it, we need to handle it.
                // If success, parseFromBlob handles it.
                // Actually relying on parseFromBlob finally block is tricky if we don't call it.
                // We should ensure isParsing is false if we error here.
                // But parseFromBlob sets isParsing=true again.
            }
        }
    }, [parseFromBlob]);

    return {
        workbookData,
        sheetNames,
        activeSheet,
        setActiveSheet,
        isParsing,
        parseError,
        parseFromUrl,
        parseFromBlob,
        reset
    };
}

/**
 * useFeatureFlag Hook
 * React hook for checking feature flag state with automatic re-renders.
 */

import { useState, useEffect } from 'react';
import { featureFlags, FeatureFlag } from '../services';

/**
 * Hook to check if a feature flag is enabled.
 * Automatically re-renders when the flag state changes.
 * 
 * @example
 * const showDebug = useFeatureFlag('SHOW_DEBUG_PANEL');
 * if (showDebug) { ... }
 */
export const useFeatureFlag = (flag: FeatureFlag): boolean => {
    const [enabled, setEnabled] = useState(() => featureFlags.isEnabled(flag));

    useEffect(() => {
        // Subscribe to changes
        const unsubscribe = featureFlags.subscribe(flag, setEnabled);

        // Update in case it changed since initial render
        setEnabled(featureFlags.isEnabled(flag));

        return unsubscribe;
    }, [flag]);

    return enabled;
};

/**
 * Hook to get all feature flags with their current values.
 * Useful for admin/debug panels.
 */
export const useAllFeatureFlags = (): Record<FeatureFlag, boolean> => {
    const [flags, setFlags] = useState(() => featureFlags.getAll());

    useEffect(() => {
        // Simple approach: poll on interval for debug purposes
        const interval = setInterval(() => {
            setFlags(featureFlags.getAll());
        }, 1000);

        return () => clearInterval(interval);
    }, []);

    return flags;
};

/**
 * useHandoffManagement Hook
 * Manages nursing handoff checklists, novedades, and staff identification.
 */

import { useCallback } from 'react';
import { DailyRecord } from '../types';
import { BEDS } from '../constants';
import { useNotification } from '../context/UIContext';
import { getPreviousDay } from '../services/repositories/DailyRecordRepository';
import { formatHandoffMessage, sendWhatsAppMessage } from '../services/integrations/whatsapp/whatsappService';
import { useAuditContext } from '../context/AuditContext';
import { getAttributedAuthors } from '../services/admin/attributionService';

export interface HandoffManagementActions {
    updateHandoffChecklist: (shift: 'day' | 'night', field: string, value: boolean | string) => void;
    updateHandoffNovedades: (shift: 'day' | 'night' | 'medical', value: string) => void;
    updateHandoffStaff: (shift: 'day' | 'night', type: 'delivers' | 'receives' | 'tens', staffList: string[]) => void;
    updateMedicalSignature: (doctorName: string) => Promise<void>;
    updateMedicalHandoffDoctor: (doctorName: string) => Promise<void>;
    markMedicalHandoffAsSent: (doctorName?: string) => Promise<void>;
    sendMedicalHandoff: (templateContent: string, targetGroupId: string) => Promise<void>;
}

export const useHandoffManagement = (
    record: DailyRecord | null,
    saveAndUpdate: (updatedRecord: DailyRecord) => Promise<void>,
    patchRecord: (partial: Record<string, any>) => Promise<void>
): HandoffManagementActions => {
    const { success, error: notifyError } = useNotification();
    const { logEvent, logDebouncedEvent, userId } = useAuditContext();

    const updateHandoffChecklist = useCallback((shift: 'day' | 'night', field: string, value: boolean | string) => {
        if (!record) return;

        const updatedRecord = { ...record };

        if (shift === 'day') {
            updatedRecord.handoffDayChecklist = {
                ...updatedRecord.handoffDayChecklist,
                [field]: value
            };
        } else {
            updatedRecord.handoffNightChecklist = {
                ...updatedRecord.handoffNightChecklist,
                [field]: value
            };
        }

        updatedRecord.lastUpdated = new Date().toISOString();
        saveAndUpdate(updatedRecord);
    }, [record, saveAndUpdate]);

    const updateHandoffNovedades = useCallback((shift: 'day' | 'night' | 'medical', value: string) => {
        if (!record) return;

        const updatedRecord = { ...record };

        if (shift === 'day') {
            updatedRecord.handoffNovedadesDayShift = value;
        } else if (shift === 'night') {
            updatedRecord.handoffNovedadesNightShift = value;
        } else if (shift === 'medical') {
            updatedRecord.medicalHandoffNovedades = value;
        }

        updatedRecord.lastUpdated = new Date().toISOString();
        saveAndUpdate(updatedRecord);

        // Audit Log (Smart/Debounced)
        const authors = getAttributedAuthors(userId, record, shift === 'medical' ? undefined : (shift as 'day' | 'night'));

        const oldContent = shift === 'day'
            ? record.handoffNovedadesDayShift
            : (shift === 'night' ? record.handoffNovedadesNightShift : record.medicalHandoffNovedades);

        logDebouncedEvent(
            'HANDOFF_NOVEDADES_MODIFIED',
            'dailyRecord',
            record.date,
            {
                shift,
                value,
                changes: {
                    novedades: { old: oldContent || '', new: value }
                }
            },
            undefined,
            record.date,
            authors
        );
    }, [record, saveAndUpdate, logDebouncedEvent, userId]);

    const updateHandoffStaff = useCallback((shift: 'day' | 'night', type: 'delivers' | 'receives' | 'tens', staffList: string[]) => {
        if (!record) return;

        const updatedRecord = { ...record };

        if (shift === 'day') {
            if (type === 'delivers') {
                updatedRecord.nursesDayShift = staffList;
            } else if (type === 'receives') {
                updatedRecord.nursesNightShift = staffList;
            } else if (type === 'tens') {
                updatedRecord.tensDayShift = staffList;
            }
        } else {
            if (type === 'delivers') {
                updatedRecord.nursesNightShift = staffList;
            } else if (type === 'receives') {
                updatedRecord.handoffNightReceives = staffList;
            } else if (type === 'tens') {
                updatedRecord.tensNightShift = staffList;
            }
        }

        updatedRecord.lastUpdated = new Date().toISOString();
        saveAndUpdate(updatedRecord);
    }, [record, saveAndUpdate]);

    const updateMedicalSignature = useCallback(async (doctorName: string) => {
        if (!record) return;

        const updatedRecord = { ...record };
        const signedAt = new Date().toISOString();

        updatedRecord.medicalSignature = {
            doctorName,
            signedAt
        };

        updatedRecord.lastUpdated = new Date().toISOString();
        await saveAndUpdate(updatedRecord);

        // Audit Log
        logEvent(
            'MEDICAL_HANDOFF_SIGNED',
            'dailyRecord',
            record.date,
            {
                doctorName,
                signedAt
            },
            undefined,
            record.date
        );
    }, [record, saveAndUpdate, logEvent]);

    const updateMedicalHandoffDoctor = useCallback(async (doctorName: string): Promise<void> => {
        if (!record) return;

        const updatedRecord = { ...record };
        updatedRecord.medicalHandoffDoctor = doctorName;
        updatedRecord.lastUpdated = new Date().toISOString();
        await saveAndUpdate(updatedRecord);
    }, [record, saveAndUpdate]);

    const markMedicalHandoffAsSent = useCallback((doctorName?: string) => {
        if (!record) return Promise.resolve();

        const updates: Partial<DailyRecord> = {
            medicalHandoffSentAt: new Date().toISOString()
        };
        if (doctorName) {
            updates.medicalHandoffDoctor = doctorName;
        }
        return patchRecord(updates);
    }, [record, patchRecord]);

    const sendMedicalHandoff = useCallback(async (templateContent: string, targetGroupId: string) => {
        if (!record) return;

        try {
            // 1. Get Doctor Name (Auto-fill from previous if empty)
            let doctorName = record.medicalHandoffDoctor;
            if (!doctorName) {
                const previousRecord = await getPreviousDay(record.date);
                doctorName = previousRecord?.medicalHandoffDoctor || 'Sin especificar';
            }

            // 2. Calculate Stats (Replica of HandoffView logic)
            const activeExtras = record.activeExtraBeds || [];
            const visibleBeds = BEDS.filter(bed => !bed.isExtra || activeExtras.includes(bed.id));

            const hospitalized = visibleBeds.filter(b =>
                record.beds[b.id].patientName && !record.beds[b.id].isBlocked
            ).length;
            const blockedBeds = visibleBeds.filter(b => record.beds[b.id].isBlocked).length;
            const freeBeds = visibleBeds.length - hospitalized - blockedBeds;

            // 3. Format Message
            const [year, month, day] = record.date.split('-');
            const dateStr = `${day}-${month}-${year}`;
            const handoffUrl = `${window.location.origin}?mode=signature&date=${record.date}`;

            const message = formatHandoffMessage(templateContent, {
                date: dateStr,
                signedBy: doctorName,
                signedAt: new Date().toLocaleTimeString('es-CL', { hour: '2-digit', minute: '2-digit' }),
                hospitalized,
                freeBeds,
                newAdmissions: 0,
                discharges: 0,
                handoffUrl
            });

            // 4. Send WhatsApp
            const result = await sendWhatsAppMessage(targetGroupId, message);
            if (!result.success) {
                throw new Error(result.error);
            }

            success('WhatsApp Enviado', 'Entrega médica enviada correctamente.');

            // 5. Atomic Patch Update
            await patchRecord({
                medicalHandoffDoctor: doctorName,
                medicalHandoffSentAt: new Date().toISOString()
            });

        } catch (err: unknown) {
            console.error('WhatsApp Logic Error:', err);
            const errorMessage = err instanceof Error ? err.message : 'Error desconocido';
            notifyError('Error al enviar', errorMessage);
        }
    }, [record, patchRecord, success, notifyError]);

    return {
        updateHandoffChecklist,
        updateHandoffNovedades,
        updateHandoffStaff,
        updateMedicalSignature,
        updateMedicalHandoffDoctor,
        markMedicalHandoffAsSent,
        sendMedicalHandoff
    };
};

