const STATIC_ROLES: Record<string, string> = {
    [INSTITUTIONAL_ACCOUNTS.NURSING]: 'nurse_hospital',
    [INSTITUTIONAL_ACCOUNTS.NURSING_ALT]: 'nurse_hospital',
