const formatDateForTitle = (dateStr: string): string => {
    const date = new Date(dateStr + 'T12:00:00');
    return date.toLocaleDateString('es-CL', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric'
    });
};

/**
 * Base Storage Service
 * Shared utilities and factory functions for Firebase Storage services
 * 
 * This module provides:
 * - Common constants (MONTH_NAMES)
 * - Generic factory functions for listing years, months, and files
 * - Shared types for stored files
 */

import {
    ref,
    listAll,
    getDownloadURL,
    getMetadata,
    StorageReference
} from 'firebase/storage';
import { storage, firebaseReady } from '../../firebaseConfig';

// ============= Types =============

export interface MonthInfo {
    number: string;
    name: string;
}

export interface BaseStoredFile {
    name: string;
    fullPath: string;
    downloadUrl: string;
    date: string;
    createdAt: string;
    size: number;
}

export interface ListFilesConfig<T> {
    storageRoot: string;
    parseFilePath: (path: string) => { date: string;[key: string]: any } | null;
    mapToFile: (item: StorageReference, metadata: any, downloadUrl: string, parsed: any) => T;
}

// ============= Constants =============

export const MONTH_NAMES = [
    'Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio',
    'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'
];

// ============= Default Timeouts =============

const DEFAULT_LIST_TIMEOUT_MS = 5000;
const DEFAULT_FILES_TIMEOUT_MS = 15000;

// ============= Factory Functions =============

/**
 * Creates a function to list all years in a storage root
 */
export const createListYears = (storageRoot: string) => {
    return async (): Promise<string[]> => {
        try {
            await firebaseReady;
            if (!storage) return [];

            const timeoutPromise = new Promise<string[]>((resolve) =>
                setTimeout(() => resolve([]), DEFAULT_LIST_TIMEOUT_MS)
            );

            const listPromise = (async () => {
                const rootRef = ref(storage, storageRoot);
                const result = await listAll(rootRef);
                return result.prefixes.map(p => p.name).sort((a, b) => b.localeCompare(a));
            })();

            return await Promise.race([listPromise, timeoutPromise]);
        } catch (error) {
            console.warn(`[BaseStorage] Error listing years for ${storageRoot}:`, error);
            return [];
        }
    };
};

/**
 * Creates a function to list all months in a year
 */
export const createListMonths = (storageRoot: string) => {
    return async (year: string): Promise<MonthInfo[]> => {
        try {
            await firebaseReady;
            if (!storage) return [];

            const timeoutPromise = new Promise<MonthInfo[]>((resolve) =>
                setTimeout(() => resolve([]), DEFAULT_LIST_TIMEOUT_MS)
            );

            const listPromise = (async () => {
                const yearRef = ref(storage, `${storageRoot}/${year}`);
                const result = await listAll(yearRef);
                return result.prefixes
                    .map(p => ({
                        number: p.name,
                        name: MONTH_NAMES[parseInt(p.name) - 1] || p.name
                    }))
                    .sort((a, b) => b.number.localeCompare(a.number));
            })();

            return await Promise.race([listPromise, timeoutPromise]);
        } catch (error) {
            console.warn(`[BaseStorage] Error listing months for ${storageRoot}/${year}:`, error);
            return [];
        }
    };
};

/**
 * Creates a function to list all files in a month
 */
export const createListFilesInMonth = <T extends BaseStoredFile>(config: ListFilesConfig<T>) => {
    return async (year: string, month: string): Promise<T[]> => {
        const fullStoragePath = `${config.storageRoot}/${year}/${month}`;
        try {
            await firebaseReady;
            if (!storage) return [];

            const timeoutPromise = new Promise<T[]>((resolve) =>
                setTimeout(() => {
                    console.warn(`[BaseStorage] ⏱️ Timeout reached for ${fullStoragePath}`);
                    resolve([]);
                }, DEFAULT_FILES_TIMEOUT_MS)
            );

            const listPromise = (async () => {
                const monthRef = ref(storage, fullStoragePath);
                const result = await listAll(monthRef);

                if (result.items.length === 0) {
                    return [];
                }

                // console.debug(`[BaseStorage] 🔍 Found ${result.items.length} items in ${fullStoragePath}, fetching metadata in parallel...`);

                const filePromises = result.items.map(async (item) => {
                    try {
                        const [metadata, downloadUrl] = await Promise.all([
                            getMetadata(item),
                            getDownloadURL(item)
                        ]);

                        const parsed = config.parseFilePath(item.fullPath);

                        if (parsed) {
                            return config.mapToFile(item, metadata, downloadUrl, parsed);
                        } else {
                            console.warn(`[BaseStorage] ⚠️ File skipped (failed parsing): ${item.fullPath}`);
                            return null;
                        }
                    } catch (error) {
                        console.error(`[BaseStorage] ‼️ Error getting file info: ${item.name}`, error);
                        return null;
                    }
                });

                const filesWithNulls = await Promise.all(filePromises);
                const files = filesWithNulls.filter(f => f !== null) as T[];
                return files.sort((a, b) => b.date.localeCompare(a.date));
            })();

            return await Promise.race([listPromise, timeoutPromise]);
        } catch (error) {
            console.warn(`[BaseStorage] Error listing files for ${fullStoragePath}:`, error);
            return [];
        }
    };
};

/**
 * Utility: Format bytes to human-readable size
 */
export const formatFileSize = (bytes: number): string => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return Math.round(bytes / Math.pow(k, i)) + ' ' + sizes[i];
};

/**
 * Census Storage Service
 * Handles uploading and managing Census Excel files in Firebase Storage
 */

import {
    ref,
    uploadBytes,
    getDownloadURL,
    deleteObject,
    getMetadata
} from 'firebase/storage';
import { storage, auth, firebaseReady } from '../../firebaseConfig';
import {
    createListYears,
    createListMonths,
    createListFilesInMonth,
    BaseStoredFile
} from './baseStorageService';

// ============= Types =============

export interface StoredCensusFile extends BaseStoredFile {
    // Census files don't have shiftType, just the base properties
}

// ============= Constants =============

const STORAGE_ROOT = 'censo-diario';

// ============= Helper Functions =============

/**
 * Generate file path for a Census Excel
 */
const generateCensusPath = (date: string): string => {
    const [year, month, day] = date.split('-'); // input date is YYYY-MM-DD
    const formattedDate = `${day}-${month}-${year}`;
    const filename = `${formattedDate} - Censo Diario.xlsx`;
    return `${STORAGE_ROOT}/${year}/${month}/${filename}`;
};

/**
 * Parse file path to extract date
 */
const parseFilePath = (path: string): { date: string } | null => {
    // Check if path ends with "DD-MM-YYYY - Censo Diario.xlsx"
    const match = path.match(/(\d{2})-(\d{2})-(\d{4}) - Censo Diario\.xlsx$/);
    if (match) {
        return {
            date: `${match[3]}-${match[2]}-${match[1]}` // Convert back to YYYY-MM-DD
        };
    }
    return null;
};

// ============= Core Functions =============

/**
 * Upload a Census Excel to Firebase Storage
 */
export const uploadCensus = async (
    excelBlob: Blob,
    date: string
): Promise<string> => {
    // console.info(`[CensusStorage] Starting upload for ${date}...`);
    await firebaseReady;

    const filePath = generateCensusPath(date);
    const storageRef = ref(storage, filePath);

    const user = auth.currentUser;
    const metadata = {
        contentType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        customMetadata: {
            date,
            uploadedBy: user?.email || 'unknown',
            uploadedAt: new Date().toISOString()
        }
    };

    await uploadBytes(storageRef, excelBlob, metadata);
    const downloadUrl = await getDownloadURL(storageRef);

    // console.info(`✅ [CensusStorage] Upload complete: ${filePath}`);
    return downloadUrl;
};

/**
 * Check if a Census file exists for a given date
 */
export const checkCensusExists = async (date: string): Promise<boolean> => {
    try {
        await firebaseReady;
        const filePath = generateCensusPath(date);
        const storageRef = ref(storage, filePath);
        await getMetadata(storageRef);
        return true;
    } catch (error: any) {
        // If file doesn't exist, getMetadata throws
        if (error.code === 'storage/object-not-found') {
            return false;
        }
        console.warn('[CensusStorage] Error checking file existence:', error);
        return false;
    }
};

/**
 * Delete a Census file from Storage
 */
export const deleteCensusFile = async (date: string): Promise<void> => {
    const filePath = generateCensusPath(date);
    const storageRef = ref(storage, filePath);
    await deleteObject(storageRef);
    // console.info(`🗑️ Census deleted: ${filePath}`);
};

/**
 * List all years with Census files (using base service)
 */
export const listCensusYears = createListYears(STORAGE_ROOT);

/**
 * List all months in a year for Census (using base service)
 */
export const listCensusMonths = createListMonths(STORAGE_ROOT);

/**
 * List all Census files in a month (using base service)
 * Note: Display name is normalized to format (DD-MM-YYYY - Censo Diario.xlsx)
 */
export const listCensusFilesInMonth = createListFilesInMonth<StoredCensusFile>({
    storageRoot: STORAGE_ROOT,
    parseFilePath,
    mapToFile: (item, metadata, downloadUrl, parsed) => {
        // Generate normalized display name from parsed date
        const [year, month, day] = parsed.date.split('-');
        const displayName = `${day}-${month}-${year} - Censo Diario.xlsx`;

        return {
            name: displayName, // Always use normalized format for display
            fullPath: item.fullPath,
            downloadUrl,
            date: parsed.date,
            createdAt: metadata.customMetadata?.uploadedAt || metadata.timeCreated,
            size: metadata.size
        };
    }
});

/**
 * CUDYR Storage Service
 * Handles uploading CUDYR Excel files to Firebase Storage
 * 
 * Storage structure:
 * cudyr-backup/
 *   2026/
 *     01/
 *       08-01-2026 - CUDYR.xlsx
 */

import {
    ref,
    uploadBytes,
    getDownloadURL,
    getMetadata
} from 'firebase/storage';
import { storage, auth, firebaseReady } from '../../firebaseConfig';
import {
    createListYears,
    createListMonths,
    createListFilesInMonth,
    BaseStoredFile
} from './baseStorageService';

// ============= Types =============

export interface StoredCudyrFile extends BaseStoredFile {
    month: string;
    year: string;
}

// ============= Constants =============

const STORAGE_ROOT = 'cudyr-backup';

// ============= Helper Functions =============

/**
 * Generate file path for a CUDYR Excel backup
 * New format: DD-MM-YYYY - CUDYR.xlsx
 */
const generateCudyrPath = (date: string): string => {
    const [year, month, day] = date.split('-');
    const formattedDate = `${day}-${month}-${year}`;
    const filename = `${formattedDate} - CUDYR.xlsx`;
    return `${STORAGE_ROOT}/${year}/${month}/${filename}`;
};

/**
 * Parse file path to extract metadata
 * Supports both old format (CUDYR_DD-MM-YYYY.xlsx) and new format (DD-MM-YYYY - CUDYR.xlsx)
 */
const parseFilePath = (path: string): { date: string; year: string; month: string } | null => {
    // New format: DD-MM-YYYY - CUDYR.xlsx
    const newMatch = path.match(/(\d{2})-(\d{2})-(\d{4}) - CUDYR\.xlsx$/);
    if (newMatch) {
        return {
            date: `${newMatch[3]}-${newMatch[2]}-${newMatch[1]}`, // YYYY-MM-DD
            year: newMatch[3],
            month: newMatch[2]
        };
    }

    // Old format: CUDYR_DD-MM-YYYY.xlsx (backwards compatibility)
    const oldMatch = path.match(/CUDYR_(\d{2})-(\d{2})-(\d{4})\.xlsx$/);
    if (oldMatch) {
        return {
            date: `${oldMatch[3]}-${oldMatch[2]}-${oldMatch[1]}`, // YYYY-MM-DD
            year: oldMatch[3],
            month: oldMatch[2]
        };
    }
    return null;
};

// ============= Core Functions =============

/**
 * Upload a CUDYR Excel to Firebase Storage
 */
export const uploadCudyrExcel = async (
    excelBlob: Blob,
    date: string
): Promise<string> => {
    // console.info(`[CudyrStorage] Starting upload for ${date}...`);
    await firebaseReady;

    if (!storage) {
        throw new Error('Firebase Storage not initialized');
    }

    const filePath = generateCudyrPath(date);

    // Check for and delete legacy file to prevent duplicates (CUDYR_DD-MM-YYYY.xlsx)
    try {
        const [d, m, y] = date.split('-');
        const legacyFilename = `CUDYR_${d}-${m}-${y}.xlsx`;
        const legacyPath = `${STORAGE_ROOT}/${y}/${m}/${legacyFilename}`;
        const legacyRef = ref(storage, legacyPath);

        // Check if legacy file exists
        await getMetadata(legacyRef);

        // If found, delete it
        // console.debug(`[CudyrStorage] Found legacy duplicate: ${legacyPath}, deleting...`);
        const { deleteObject } = await import('firebase/storage');
        await deleteObject(legacyRef);
        // console.debug(`[CudyrStorage] ✅ Legacy duplicate deleted`);
    } catch (_ignore) {
        // Legacy file doesn't exist, proceed normally
    }

    const storageRef = ref(storage, filePath);

    const user = auth.currentUser;
    const metadata = {
        contentType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        customMetadata: {
            date,
            uploadedBy: user?.email || 'unknown',
            uploadedAt: new Date().toISOString()
        }
    };

    await uploadBytes(storageRef, excelBlob, metadata);
    const downloadUrl = await getDownloadURL(storageRef);

    // console.info(`✅ [CudyrStorage] Upload complete: ${filePath}`);
    return downloadUrl;
};

/**
 * Check if a CUDYR backup exists for a date
 */
export const cudyrExists = async (date: string): Promise<boolean> => {
    const TIMEOUT_MS = 4000;
    const timeoutPromise = new Promise<boolean>((resolve) =>
        setTimeout(() => resolve(false), TIMEOUT_MS)
    );

    const checkPromise = (async (): Promise<boolean> => {
        try {
            await firebaseReady;
            if (!storage) return false;

            const filePath = generateCudyrPath(date);
            const storageRef = ref(storage, filePath);

            await getMetadata(storageRef);
            return true;
        } catch (error: any) {
            if (error?.code === 'storage/object-not-found') {
                return false;
            }
            console.warn(`[CudyrStorage] Error checking:`, error.message || error);
            return false;
        }
    })();

    return await Promise.race([checkPromise, timeoutPromise]);
};

/**
 * Delete a CUDYR file from Storage
 */
export const deleteCudyrFile = async (date: string): Promise<void> => {
    const { deleteObject } = await import('firebase/storage');
    const filePath = generateCudyrPath(date);
    const storageRef = ref(storage, filePath);
    await deleteObject(storageRef);
    // console.info(`🗑️ CUDYR deleted: ${filePath}`);
};

