export const checkEmailAuthorization = async (email: string): Promise<CensusAuthorizedEmail | null> => {
    try {
        await firebaseReady;
        if (!db) return null;
        const docRef = doc(db, AUTHORIZED_EMAILS_COLLECTION, email.toLowerCase().trim());
        const snap = await getDoc(docRef);

        if (snap.exists()) {
            return snap.data() as CensusAuthorizedEmail;
        }
        return null;
    } catch (err) {
        console.error('Error checking email authorization', err);
        return null;
    }
};

/**
 * Extends checkUserAccess to also check for email authorization
 */
export const checkUserAccessWithWhitelist = async (
    userId: string,
    email: string,
    displayName: string
): Promise<CensusAccessUser | null> => {
    try {
        // 1. Check if user already exists in access list
        const existingUser = await checkUserAccess(userId);
        if (existingUser) return existingUser;

        // 2. If not, check if their email is authorized in whitelist
        const authInfo = await checkEmailAuthorization(email);
        if (authInfo) {
            // 3. Auto-register them!
            const newUser: CensusAccessUser = {
                id: userId,
                email: email.toLowerCase(),
                displayName,
                role: authInfo.role,
                createdAt: new Date(),
                createdBy: authInfo.addedBy,
                expiresAt: calculateDefaultExpiration(),
                isActive: true
            };

            await firebaseReady;
            if (!db) return null;
            await setDoc(doc(db, USERS_COLLECTION, userId), newUser);

            return newUser;
        }

        return null;
    } catch (err) {
        console.error('Error in checkUserAccessWithWhitelist', err);
        return null;
    }
};

/**
 * Census Master Export Service
 * Generates a multi-sheet Excel file with one sheet per day of the month.
 * Uses the shared workbook builder to keep the email attachment and manual download in sync.
 * 
 * NOTE: Password encryption only works for email attachments (server-side via Netlify Function).
 * Manual downloads are NOT encrypted because xlsx-populate doesn't work in browsers.
 */

import { saveAs } from 'file-saver';
import { DailyRecord } from '../../types';
import { MONTH_NAMES } from '../../constants';
import { getMonthRecordsFromFirestore } from '../storage/firestoreService';
import { getStoredRecords } from '../storage/localStorageService';
import { isFirestoreEnabled } from '../repositories/DailyRecordRepository';
import { buildCensusMasterWorkbook, getCensusMasterFilename } from './censusMasterWorkbook';
import { validateExcelExport, XLSX_MIME_TYPE } from './excelValidation';

/**
 * Generate and download the Census Master Excel file for a given month.
 * Fetches data from Firestore if available, otherwise falls back to localStorage.
 * Creates one worksheet per day that has data, from the first day up to the selected day.
 * 
 * NOTE: This download is NOT password-protected. Only email attachments are encrypted.
 * 
 * @param year - Year (e.g., 2025)
 * @param month - Month (0-indexed, e.g., 11 for December)
 * @param selectedDay - Day of the month to use as the limit (e.g., 10 means include days 1-10)
 * @throws Error if the generated Excel file is invalid
 */
export const generateCensusMasterExcel = async (year: number, month: number, selectedDay: number): Promise<void> => {
    const limitDateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const monthPrefix = `${year}-${String(month + 1).padStart(2, '0')}`;

    let allMonthRecords: DailyRecord[] = [];

    try {
        if (isFirestoreEnabled()) {
            console.info(`📊 Cargando datos del mes ${MONTH_NAMES[month]} ${year} desde Firestore...`);
            allMonthRecords = await getMonthRecordsFromFirestore(year, month);
        } else {
            console.info(`📊 Cargando datos del mes ${MONTH_NAMES[month]} ${year} desde almacenamiento local...`);
            const localRecords = getStoredRecords();
            allMonthRecords = Object.values(localRecords).filter(r => r.date.startsWith(monthPrefix));
        }

        const monthRecords = allMonthRecords
            .filter(record => record.date <= limitDateStr)
            .sort((a, b) => a.date.localeCompare(b.date));

        if (monthRecords.length === 0) {
            console.warn(`No hay datos para ${MONTH_NAMES[month]} ${year}`);
            alert(`No hay datos registrados para las fechas seleccionadas en ${MONTH_NAMES[month]} ${year}`);
            return;
        }

        console.info(`✅ Se encontraron ${monthRecords.length} días con datos`);

        // Generate the workbook (without encryption - xlsx-populate doesn't work in browsers)
        const workbook = await buildCensusMasterWorkbook(monthRecords);
        const buffer = await workbook.xlsx.writeBuffer();
        const filename = getCensusMasterFilename(limitDateStr);

        // Validate before creating blob and downloading
        const validation = validateExcelExport(buffer, filename);
        if (!validation.valid) {
            console.error(`❌ Validación de Excel fallida: ${validation.error}`);
            alert(`Error al generar el archivo Excel:\n${validation.error}\n\nPor favor, recarga la página e intenta de nuevo.`);
            return;
        }

        const blob = new Blob([buffer], { type: XLSX_MIME_TYPE });
        saveAs(blob, filename);

        console.info(`📥 Archivo descargado: ${filename} (${buffer.byteLength} bytes)`);
    } catch (error) {
        console.error('❌ Error generando Excel:', error);
        const message = error instanceof Error ? error.message : 'Error desconocido';
        alert(`Error al generar el archivo Excel:\n${message}\n\nPor favor, recarga la página e intenta de nuevo.`);
        throw error;
    }
};

import {
    collection,
    doc,
    getDoc,
    getDocs,
    setDoc,
    updateDoc,
    deleteDoc,
    onSnapshot,
    query,
    where,
    orderBy,
    limit,
    writeBatch,
    QueryConstraint as FirebaseQueryConstraint,
    startAfter
} from 'firebase/firestore';
import { db as firebaseDb } from '../../../firebaseConfig';
import {
    IDatabaseProvider,
    QueryOptions,
    IDatabaseBatch
} from './types';

export class FirestoreProvider implements IDatabaseProvider {
    constructor() {
        // We no longer capture db here to avoid initialization race conditions
    }

    async getDoc<T>(collectionName: string, id: string): Promise<T | null> {
        const docRef = doc(firebaseDb, collectionName, id);
        const docSnap = await getDoc(docRef);
        return docSnap.exists() ? (docSnap.data() as T) : null;
    }

    async getDocs<T>(collectionName: string, options?: QueryOptions): Promise<T[]> {
        const constraints = this.buildConstraints(options);
        const q = query(collection(firebaseDb, collectionName), ...constraints);
        const snapshot = await getDocs(q);
        return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as T));
    }

    async setDoc<T>(collectionName: string, id: string, data: T): Promise<void> {
        const docRef = doc(firebaseDb, collectionName, id);
        await setDoc(docRef, data as any);
    }

    async updateDoc(collectionName: string, id: string, data: Record<string, any>): Promise<void> {
        const docRef = doc(firebaseDb, collectionName, id);
        await updateDoc(docRef, data);
    }

    async deleteDoc(collectionName: string, id: string): Promise<void> {
        const docRef = doc(firebaseDb, collectionName, id);
        await deleteDoc(docRef);
    }

    subscribeDoc<T>(collectionName: string, id: string, callback: (data: T | null) => void): () => void {
        const docRef = doc(firebaseDb, collectionName, id);
        return onSnapshot(docRef, (docSnap) => {
            callback(docSnap.exists() ? (docSnap.data() as T) : null);
        });
    }

    subscribeQuery<T>(collectionName: string, options: QueryOptions, callback: (data: T[]) => void): () => void {
        const constraints = this.buildConstraints(options);
        const q = query(collection(firebaseDb, collectionName), ...constraints);
        return onSnapshot(q, (snapshot) => {
            callback(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as T)));
        });
    }

    async runBatch(operations: (batch: IDatabaseBatch) => void): Promise<void> {
        const batch = writeBatch(firebaseDb);
        const dbBatch: IDatabaseBatch = {
            set: (col, id, data) => batch.set(doc(firebaseDb, col, id), data as any),
            update: (col, id, data) => batch.update(doc(firebaseDb, col, id), data),
            delete: (col, id) => batch.delete(doc(firebaseDb, col, id))
        };
        operations(dbBatch);
        await batch.commit();
    }

    private buildConstraints(options?: QueryOptions): FirebaseQueryConstraint[] {
        const constraints: FirebaseQueryConstraint[] = [];

        if (options?.where) {
            options.where.forEach(w => {
                constraints.push(where(w.field, w.operator, w.value));
            });
        }

        if (options?.orderBy) {
            options.orderBy.forEach(o => {
                constraints.push(orderBy(o.field, o.direction));
            });
        }

        if (options?.limit) {
            constraints.push(limit(options.limit));
        }

        if (options?.startAfter) {
            constraints.push(startAfter(options.startAfter));
        }

        return constraints;
    }
}

import { DailyRecord, ShiftType } from '../../types';
import { formatDateDDMMYYYY } from '../dataService';
import {
    getBase64ImageFromURL,
    Schedule,
    getHandoffStaffInfo
} from './handoffPdfUtils';
import {
    addPatientTable,
    addMovementsSummary,
    addCudyrTable
} from './handoffPdfSections';

/**
 * Generate a lightweight PDF for the Handoff report.
 * Supports both Medical and Nursing formats.
 */
export const generateHandoffPdf = async (
    record: DailyRecord,
    isMedical: boolean,
    selectedShift: ShiftType,
    schedule: Schedule
) => {
    // Dynamic imports to reduce bundle size
    const [{ default: jsPDF }, { default: autoTable }] = await Promise.all([
        import('jspdf'),
        import('jspdf-autotable')
    ]);

    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.width;
    const pageHeight = doc.internal.pageSize.height;
    const margin = 14;
    const logoSize = 10;

    // 1. HEADER
    try {
        const logoData = await getBase64ImageFromURL('/images/logos/logo_HHR.png');
        doc.addImage(logoData, 'PNG', margin, margin, logoSize, logoSize);
    } catch (e) {
        console.warn("Could not load logo for PDF", e);
    }

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(14);
    const title = isMedical
        ? 'ENTREGA DE TURNO MÉDICO'
        : `ENTREGA TURNO ENFERMERÍA - ${selectedShift === 'day' ? 'LARGO' : 'NOCHE'}`;
    doc.text(title, margin + logoSize + 4, margin + 4);

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text('HOSPITAL HANGA ROA', margin + logoSize + 4, margin + 9);

    // Date & Shift Info (Right aligned)
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    const dateStr = formatDateDDMMYYYY(record.date);
    doc.text(dateStr, pageWidth - margin, margin + 4, { align: 'right' });

    doc.setFontSize(9);
    doc.setFont('helvetica', 'italic');
    const shiftLabel = selectedShift === 'day' ? 'TURNO LARGO' : 'TURNO NOCHE';
    const shiftHours = selectedShift === 'day'
        ? `(${schedule?.dayStart || '08:00'} - ${schedule?.dayEnd || '20:00'})`
        : `(${schedule?.nightStart || '20:00'} - ${schedule?.nightEnd || '08:00'})`;

    if (!isMedical) {
        doc.text(`${shiftLabel} ${shiftHours}`, pageWidth - margin, margin + 9, { align: 'right' });
    }

    // Nurse/Staff Info
    let currentY = margin + 18;
    if (!isMedical) {
        const { delivers, receives, tens } = getHandoffStaffInfo(record, selectedShift);
        const COLUMN_DELIVERS_X = margin;
        const COLUMN_RECEIVES_X = margin + 65;
        const COLUMN_TENS_X = margin + 125;
        const COLUMN_WIDTH = 55; // For wrapping

        doc.setFontSize(8);
        doc.setFont('helvetica', 'bolditalic');
        doc.text('ENFERMERO(A) ENTREGA:', COLUMN_DELIVERS_X, currentY);
        doc.text('ENFERMERO(A) RECIBE:', COLUMN_RECEIVES_X, currentY);
        doc.text('TENS DE TURNO:', COLUMN_TENS_X, currentY);

        currentY += 4;
        doc.setFont('helvetica', 'normal');

        // Wrap names to avoid truncation
        const deliversText = delivers.filter(Boolean).join(', ') || '-';
        const receivesText = receives.filter(Boolean).join(', ') || '-';
        const tensText = tens.filter(Boolean).join(', ') || '-';

        const deliversWrapped = doc.splitTextToSize(deliversText, COLUMN_WIDTH);
        const receivesWrapped = doc.splitTextToSize(receivesText, COLUMN_WIDTH);
        const tensWrapped = doc.splitTextToSize(tensText, COLUMN_WIDTH + 15); // Extra space for TENS

        doc.text(deliversWrapped, COLUMN_DELIVERS_X, currentY);
        doc.text(receivesWrapped, COLUMN_RECEIVES_X, currentY);
        doc.text(tensWrapped, COLUMN_TENS_X, currentY);

        // Max lines to calculate Y spacing
        const maxLines = Math.max(deliversWrapped.length, receivesWrapped.length, tensWrapped.length);
        currentY += (maxLines * 4) + 1;

        // 2. CHECKLIST (Only Nursing)
        const checklist = selectedShift === 'day' ? record.handoffDayChecklist : record.handoffNightChecklist;
        if (checklist) {
            const checklistItems: string[] = [];
            const cl = checklist as any;
            if (selectedShift === 'day') {
                if (cl.escalaBraden) checklistItems.push('Escala Braden: OK');
                if (cl.escalaRiesgoCaidas) checklistItems.push('Riesgo Caidas: OK');
                if (cl.escalaRiesgoLPP) checklistItems.push('Evaluacion LPP: OK');
            } else {
                if (cl.estadistica) checklistItems.push('Estadistica: OK');
                if (cl.categorizacionCudyr) checklistItems.push('Categorizacion CUDYR: OK');
                if (cl.encuestaUTI) checklistItems.push('Encuesta UTI: OK');
                if (cl.encuestaMedias) checklistItems.push('Encuesta Medias: OK');
                if (cl.conteoMedicamento) checklistItems.push('Farmacos Controlados: OK');
                if (cl.conteoNoControlados) {
                    const proxDate = cl.conteoNoControladosProximaFecha;
                    checklistItems.push(`Farmacos No-Controlados: OK${proxDate ? ` (PROX: ${formatDateDDMMYYYY(proxDate)})` : ''}`);
                }
            }
            doc.setFontSize(6);
            doc.setFont('helvetica', 'bold');
            doc.text(checklistItems.length > 0 ? `CHECKLIST: ${checklistItems.join(' | ')}` : 'CHECKLIST: Sin items completados', margin, currentY);
            currentY += 4;
        }
    }

    // 3. PATIENT TABLE
    currentY = addPatientTable(doc, record, isMedical, selectedShift, currentY, autoTable);
    currentY += 8;

    // 4. MOVIMIENTOS DEL DÍA
    currentY = addMovementsSummary(doc, record, margin, currentY, autoTable);
    currentY += 4;

    // 5. NOVEDADES
    const novedadesText = isMedical
        ? record.medicalHandoffNovedades
        : (selectedShift === 'day' ? record.handoffNovedadesDayShift : record.handoffNovedadesNightShift);

    if (novedadesText) {
        if (currentY + 30 > pageHeight) { doc.addPage(); currentY = margin; }
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(10);
        doc.text('NOVEDADES DEL TURNO', margin, currentY);
        currentY += 4;
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(9);

        const lines = novedadesText.split(/\r?\n/);
        let novedadesY = currentY;
        for (const line of lines) {
            if (line.trim() === '') { novedadesY += 2; }
            else {
                const cleanLine = line.replace(/[\u0000-\u001F\u007F-\u009F]/g, "");
                const wrappedLines = doc.splitTextToSize(cleanLine, pageWidth - (margin * 2));
                doc.text(wrappedLines, margin, novedadesY);
                novedadesY += (wrappedLines.length * 4);
            }
            if (novedadesY > pageHeight - margin) { doc.addPage(); novedadesY = margin; }
        }
        currentY = novedadesY + 6;
    }

    // 6. CUDYR (Only Nursing Night)
    if (!isMedical && selectedShift === 'night') {
        addCudyrTable(doc, record, margin, autoTable);
    }

    // 7. PAGE NUMBERS
    const pageCount = doc.getNumberOfPages();
    doc.setFontSize(8);
    doc.setFont('helvetica', 'italic');
    doc.setTextColor(100, 100, 100);
    for (let i = 1; i <= pageCount; i++) {
        doc.setPage(i);
        doc.text(`Página ${i} de ${pageCount}`, pageWidth - margin, pageHeight - margin + 4, { align: 'right' });
    }

    // Output: Trigger Print Dialog Directly (using hidden iframe)
    const blob = doc.output('blob');
    const url = URL.createObjectURL(blob);

    const iframe = document.createElement('iframe');
    iframe.style.position = 'fixed';
    iframe.style.right = '0';
    iframe.style.bottom = '0';
    iframe.style.width = '0';
    iframe.style.height = '0';
    iframe.style.border = '0';
    iframe.src = url;

    document.body.appendChild(iframe);

    iframe.onload = () => {
        iframe.contentWindow?.focus();
        iframe.contentWindow?.print();
        // Note: We don't remove the iframe immediately to allow print to finish
        setTimeout(() => {
            URL.revokeObjectURL(url);
            document.body.removeChild(iframe);
        }, 10 * 60 * 1000); // Wait 10 min or next refresh
    };
};

import type { jsPDF } from 'jspdf';
// import autoTable from 'jspdf-autotable'; // Removed static import
import { DailyRecord, PatientData, ShiftType, CudyrScore, DeviceDetails } from '../../types';
import { BEDS } from '../../constants';
import { formatDateDDMMYYYY } from '../dataService';
import { calculateHospitalizedDays } from './handoffPdfUtils';

// ============================================================================
// Section: Patient Table
// ============================================================================

// Local interfaces for jsPDF-AutoTable to avoid 'any'
interface CellHookData {
    section: 'head' | 'body' | 'foot';
    column: { index: number };
    cell: {
        raw: string | number;
        x: number;
        y: number;
        width: number;
        height: number;
        styles: {
            textColor?: number | number[];
            fontStyle?: string;
            fillColor?: number | number[];
        };
    };
    row: { index: number };
}

type AutoTableFunction = (doc: jsPDF, options: unknown) => void;

// Augmented jsPDF type for AutoTable plugin
type JsPDFWithAutoTable = jsPDF & { lastAutoTable: { finalY: number } };

export const addPatientTable = (
    doc: jsPDF,
    record: DailyRecord,
    isMedical: boolean,
    selectedShift: ShiftType,
    currentY: number,
    autoTable: AutoTableFunction
) => {
    const tableHeaders = [['Cama', 'Paciente', 'Diagnóstico', 'Est', 'DMI', 'Observaciones']];
    type TableRow = (string | { content: string; colSpan?: number; styles?: Record<string, unknown>; } | { content: string; styles: Record<string, unknown> })[] & { _daysStr?: string };
    const tableBody: TableRow[] = [];

    const formatDevices = (p: PatientData): string => {
        if (!p.devices || !Array.isArray(p.devices) || p.devices.length === 0) return '';
        return p.devices.map((d: string) => {
            const detail = p.deviceDetails?.[d as keyof DeviceDetails];
            let daysStr = '';
            if (detail?.installationDate) {
                const diffDays = calculateHospitalizedDays(detail.installationDate, record.date);
                if (diffDays && diffDays > 0) daysStr = ` (${diffDays}d)`;
            }
            return `${d}${daysStr}`;
        }).join(', ');
    };

    BEDS.forEach(bedDef => {
        const patient = record.beds[bedDef.id];
        if (!patient || !patient.patientName) return;

        const admission = patient.admissionDate ? formatDateDDMMYYYY(patient.admissionDate) : '';
        const daysHosp = calculateHospitalizedDays(patient.admissionDate, record.date);
        const daysStr = daysHosp ? `${daysHosp}d` : '';

        const observation = isMedical
            ? (patient.medicalHandoffNote || '')
            : (selectedShift === 'day' ? (patient.handoffNoteDayShift || '') : (patient.handoffNoteNightShift || ''));

        const devicesStr = formatDevices(patient);

        const row: TableRow = [
            { content: bedDef.name, styles: { halign: 'center', fontStyle: 'bold', valign: 'top' } },
            { content: `${patient.patientName}\n${patient.rut || ''} ${patient.age ? `(${patient.age})` : ''}\nFI: ${admission}`, styles: { fontStyle: 'normal' } },
            patient.pathology || '',
            patient.status || '',
            devicesStr,
            observation
        ];
        (row as unknown as { _daysStr: string })._daysStr = daysStr;
        tableBody.push(row);

        if (patient.clinicalCrib && patient.clinicalCrib.patientName) {
            const crib = patient.clinicalCrib;
            const cribObservation = isMedical
                ? (crib.medicalHandoffNote || '')
                : (selectedShift === 'day' ? (crib.handoffNoteDayShift || '') : (crib.handoffNoteNightShift || ''));
            const cribDevices = formatDevices(crib);
            const cribAdmission = crib.admissionDate ? formatDateDDMMYYYY(crib.admissionDate) : '';

            tableBody.push([
                { content: 'Cuna', styles: { halign: 'center', textColor: [236, 72, 153] } },
                { content: `${crib.patientName} (RN)\nFI: ${cribAdmission}`, styles: { textColor: [236, 72, 153], fontStyle: 'normal' } },
                crib.pathology || '',
                crib.status || '',
                cribDevices,
                cribObservation
            ]);
        }
    });

    if (tableBody.length === 0) {
        tableBody.push([{ content: 'No hay pacientes registrados.', colSpan: 6, styles: { halign: 'center' } }]);
    }

    autoTable(doc, {
        startY: currentY,
        head: tableHeaders,
        body: tableBody,
        theme: 'plain',
        styles: { fontSize: 8, cellPadding: 1, lineColor: [200, 200, 200], lineWidth: 0.1, overflow: 'linebreak' },
        headStyles: { fillColor: [240, 240, 240], textColor: 0, fontStyle: 'bold', lineWidth: 0.1, lineColor: [180, 180, 180] },
        columnStyles: { 0: { cellWidth: 15 }, 1: { cellWidth: 35 }, 2: { cellWidth: 40 }, 3: { cellWidth: 15 }, 4: { cellWidth: 25 }, 5: { cellWidth: 'auto' } },
        didParseCell: (data: unknown) => {
            const hookData = data as CellHookData;
            if (hookData.section === 'body' && hookData.column.index === 3) {
                const status = (hookData.cell.raw as string || '').toLowerCase();
                if (status === 'grave') { hookData.cell.styles.textColor = [185, 28, 28]; hookData.cell.styles.fontStyle = 'bold'; }
                else if (status === 'de cuidado') { hookData.cell.styles.textColor = [194, 65, 12]; }
                else if (status === 'estable') { hookData.cell.styles.textColor = [21, 128, 61]; }
            }
        },
        didDrawCell: (data: unknown) => {
            const hookData = data as CellHookData;
            if (hookData.section === 'body' && hookData.column.index === 0) {
                const rowData = tableBody[hookData.row.index];
                const daysStr = (rowData as unknown as { _daysStr: string })._daysStr;
                if (daysStr) {
                    doc.setFontSize(7);
                    doc.setFont('helvetica', 'normal');
                    doc.setTextColor(120, 120, 120);
                    doc.text(daysStr, hookData.cell.x + hookData.cell.width / 2, hookData.cell.y + hookData.cell.height - 2, { align: 'center' });
                    doc.setTextColor(0, 0, 0);
                }
            }
        }
    });

    return (doc as JsPDFWithAutoTable).lastAutoTable.finalY || currentY;
};

