/**
 * Generates a DOCX document using a template and patient data.
 */
export const generateDocxFromTemplate = async (
    templateBlob: Blob,
    tags: Record<string, any>
): Promise<Blob> => {
    const arrayBuffer = await templateBlob.arrayBuffer();
    const zip = new PizZip(arrayBuffer);

    const doc = new Docxtemplater(zip, {
        paragraphLoop: true,
        linebreaks: true,
        delimiters: {
            start: '{{',
            end: '}}'
        }
    });

    // Render the document (replace tags)
    doc.render(tags);

    // Output as Blob
    const out = doc.getZip().generate({
        type: 'blob',
        mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    });

    return out;
};

/**
 * Generates an XLSX document using a template and patient data.
 * It searches for {{tag}} in all cells and replaces them.
 */
export const generateXlsxFromTemplate = async (
    templateBlob: Blob,
    tags: Record<string, any>
): Promise<Blob> => {
    // Dynamic import
    const { Workbook } = await import('exceljs');
    const workbook = new Workbook();
    const arrayBuffer = await templateBlob.arrayBuffer();
    await workbook.xlsx.load(arrayBuffer);

    workbook.eachSheet((sheet) => {
        sheet.eachRow((row) => {
            row.eachCell((cell) => {
                if (typeof cell.value === 'string') {
                    let cellText = cell.value;
                    let modified = false;

                    // Regex to find all {{tag}} patterns
                    const matches = cellText.match(/\{\{([^}]+)\}\}/g);
                    if (matches) {
                        matches.forEach(match => {
                            const key = match.replace(/\{\{|\}\}/g, '').trim();
                            if (tags[key] !== undefined) {
                                cellText = cellText.replace(match, String(tags[key]));
                                modified = true;
                            }
                        });
                    }

                    if (modified) {
                        cell.value = cellText;
                    }
                }
            });
        });
    });

    const buffer = await workbook.xlsx.writeBuffer();
    return new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
};

/**
 * Transfer Service
 * Handles Firestore operations for transfer requests
 */

import {
    collection,
    doc,
    getDoc,
    setDoc,
    deleteDoc,
    getDocs,
    query,
    where,
    orderBy,
    onSnapshot,
    Timestamp
} from 'firebase/firestore';
import { db } from '../../firebaseConfig';
import { TransferRequest, TransferStatus, StatusChange } from '../../types/transfers';

import { getActiveHospitalId, COLLECTIONS } from '../../constants/firestorePaths';

// Collection paths
const getTransfersCollection = () => collection(
    db,
    COLLECTIONS.HOSPITALS,
    getActiveHospitalId(),
    'transferRequests'
);

const getTransferHistoryCollection = () => collection(
    db,
    COLLECTIONS.HOSPITALS,
    getActiveHospitalId(),
    'transferHistory'
);

/**
 * Generate a unique ID for new transfer requests
 */
const generateTransferId = (): string => {
    return `TR-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
};

/**
 * Convert Firestore document to TransferRequest
 */
const docToTransfer = (docData: Record<string, unknown>, docId: string): TransferRequest => {
    // Normalize status for backward compatibility
    let status = docData.status as TransferStatus;
    if (status === 'RECEIVED' as any) status = 'SENT';

    return {
        ...(docData as unknown as TransferRequest),
        id: docId,
        status,
        statusHistory: (docData.statusHistory as any[])?.map(h => ({
            ...h,
            from: h.from === 'RECEIVED' ? 'SENT' : h.from,
            to: h.to === 'RECEIVED' ? 'SENT' : h.to
        })) || [],
        requestDate: docData.requestDate instanceof Timestamp
            ? docData.requestDate.toDate().toISOString().split('T')[0]
            : (docData.requestDate as string),
        createdAt: docData.createdAt instanceof Timestamp
            ? docData.createdAt.toDate().toISOString()
            : (docData.createdAt as string),
        updatedAt: docData.updatedAt instanceof Timestamp
            ? docData.updatedAt.toDate().toISOString()
            : (docData.updatedAt as string)
    };
};

/**
 * Create a new transfer request
 */
export const createTransferRequest = async (
    data: Omit<TransferRequest, 'id' | 'createdAt' | 'updatedAt' | 'statusHistory'>
): Promise<TransferRequest> => {
    const id = generateTransferId();
    const now = new Date().toISOString();

    const transfer: TransferRequest = {
        ...data,
        id,
        status: 'REQUESTED',
        statusHistory: [{
            from: null,
            to: 'REQUESTED',
            timestamp: now,
            userId: data.createdBy
        }],
        createdAt: now,
        updatedAt: now
    };

    const docRef = doc(getTransfersCollection(), id);
    await setDoc(docRef, {
        ...transfer,
        createdAt: Timestamp.now(),
        updatedAt: Timestamp.now()
    });

    // console.info('✅ Transfer request created:', id);
    return transfer;
};

/**
 * Update an existing transfer request
 */
export const updateTransferRequest = async (
    id: string,
    data: Partial<TransferRequest>
): Promise<void> => {
    const docRef = doc(getTransfersCollection(), id);
    await setDoc(docRef, {
        ...data,
        updatedAt: Timestamp.now()
    }, { merge: true });

    // console.info('✅ Transfer request updated:', id);
};

/**
 * Change the status of a transfer request
 */
export const changeTransferStatus = async (
    id: string,
    newStatus: TransferStatus,
    userId: string,
    notes?: string
): Promise<void> => {
    const docRef = doc(getTransfersCollection(), id);
    const docSnap = await getDoc(docRef);

    if (!docSnap.exists()) {
        throw new Error(`Transfer request ${id} not found`);
    }

    const current = docSnap.data() as TransferRequest;
    const statusChange: StatusChange = {
        from: current.status,
        to: newStatus,
        timestamp: new Date().toISOString(),
        userId,
        notes
    };

    await setDoc(docRef, {
        status: newStatus,
        statusHistory: [...(current.statusHistory || []), statusChange],
        updatedAt: Timestamp.now()
    }, { merge: true });

    // console.info(`✅ Transfer ${id} status changed: ${current.status} → ${newStatus}`);
};

/**
 * Mark a transfer as completed and move to history
 */
export const completeTransfer = async (
    id: string,
    userId: string
): Promise<void> => {
    const docRef = doc(getTransfersCollection(), id);
    const docSnap = await getDoc(docRef);

    if (!docSnap.exists()) {
        throw new Error(`Transfer request ${id} not found`);
    }

    const transfer = docSnap.data() as TransferRequest;

    // Add final status change
    const statusChange: StatusChange = {
        from: transfer.status,
        to: 'TRANSFERRED',
        timestamp: new Date().toISOString(),
        userId
    };

    const completedTransfer = {
        ...transfer,
        status: 'TRANSFERRED' as TransferStatus,
        statusHistory: [...(transfer.statusHistory || []), statusChange],
        updatedAt: Timestamp.now()
    };

    // Move to history collection
    const historyRef = doc(getTransferHistoryCollection(), id);
    await setDoc(historyRef, completedTransfer);

    // Delete from active collection
    await deleteDoc(docRef);

    // console.info(`✅ Transfer ${id} completed and archived`);
};

/**
 * Get all active transfer requests
 */
export const getActiveTransfers = async (): Promise<TransferRequest[]> => {
    const q = query(
        getTransfersCollection(),
        where('status', '!=', 'TRANSFERRED'),
        orderBy('status'),
        orderBy('requestDate', 'desc')
    );

    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => docToTransfer(doc.data(), doc.id));
};

/**
 * Subscribe to active transfer requests (real-time)
 * Shows all active transfers + TRANSFERRED/CANCELLED from today
 */
export const subscribeToTransfers = (
    callback: (transfers: TransferRequest[]) => void
): (() => void) => {
    const q = query(
        getTransfersCollection(),
        orderBy('requestDate', 'desc')
    );

    return onSnapshot(q, (snapshot) => {
        const today = new Date().toISOString().split('T')[0];
        const transfers = snapshot.docs
            .map(doc => docToTransfer(doc.data(), doc.id))
            .filter(t => {
                // Always show active transfers
                if (t.status !== 'TRANSFERRED' && t.status !== 'CANCELLED') {
                    return true;
                }
                // Show TRANSFERRED/CANCELLED only if completed today
                const lastChange = t.statusHistory[t.statusHistory.length - 1];
                if (lastChange) {
                    const changeDate = lastChange.timestamp.split('T')[0];
                    return changeDate === today;
                }
                return false;
            });
        callback(transfers);
    }, (error) => {
        console.error('❌ Error subscribing to transfers:', error);
        callback([]);
    });
};

/**
 * Get a single transfer request by ID
 */
export const getTransferById = async (id: string): Promise<TransferRequest | null> => {
    const docRef = doc(getTransfersCollection(), id);
    const docSnap = await getDoc(docRef);

    if (docSnap.exists()) {
        return docToTransfer(docSnap.data(), id);
    }
    return null;
};

/**
 * Delete a transfer request (admin only)
 */
export const deleteTransferRequest = async (id: string): Promise<void> => {
    const docRef = doc(getTransfersCollection(), id);
    await deleteDoc(docRef);
    // console.info('🗑️ Transfer request deleted:', id);
};

/**
 * Delete a specific status history entry (for correcting mistakes)
 * Never allows deleting the first entry (creation)
 */
export const deleteStatusHistoryEntry = async (
    id: string,
    historyIndex: number
): Promise<void> => {
    const docRef = doc(getTransfersCollection(), id);
    const docSnap = await getDoc(docRef);

    if (!docSnap.exists()) {
        throw new Error(`Transfer request ${id} not found`);
    }

    const current = docSnap.data() as TransferRequest;
    const history = current.statusHistory || [];

    // Never delete the first entry
    if (historyIndex === 0 || historyIndex >= history.length) {
        throw new Error('Cannot delete this history entry');
    }

    // Remove the entry and update status to the previous entry's "to" value
    const newHistory = history.filter((_, idx) => idx !== historyIndex);
    const newStatus = newHistory[newHistory.length - 1]?.to || 'REQUESTED';

    await setDoc(docRef, {
        status: newStatus,
        statusHistory: newHistory,
        updatedAt: Timestamp.now()
    }, { merge: true });

    // console.info(`✅ Transfer ${id} history entry ${historyIndex} deleted, status reverted to ${newStatus}`);
};

/**
 * Logger Service
 * Centralized logging with configurable levels and structured output.
 * 
 * Features:
 * - Configurable log levels (debug, info, warn, error)
 * - Environment-aware (verbose in dev, minimal in prod)
 * - Structured log format with timestamps
 * - Context support for grouping related logs
 */

// ============================================================================
// Types
// ============================================================================

export type LogLevel = 'debug' | 'info' | 'warn' | 'error' | 'none';

export interface LogEntry {
    timestamp: string;
    level: LogLevel;
    message: string;
    context?: string;
    data?: unknown;
}

interface LoggerConfig {
    minLevel: LogLevel;
    enableTimestamps: boolean;
    enableContext: boolean;
    maxStoredEntries: number;
}

// Level priority for filtering
const LEVEL_PRIORITY: Record<LogLevel, number> = {
    debug: 0,
    info: 1,
    warn: 2,
    error: 3,
    none: 4
};

// ============================================================================
// Logger Class
// ============================================================================

class LoggerService {
    private static instance: LoggerService;
    private config: LoggerConfig;
    private entries: LogEntry[] = [];

    private constructor() {
        // Default config based on environment
        const isDev = typeof window !== 'undefined' &&
            (window.location.hostname === 'localhost' ||
                window.location.hostname === '127.0.0.1');

        this.config = {
            minLevel: isDev ? 'debug' : 'warn',
            enableTimestamps: true,
            enableContext: true,
            maxStoredEntries: 100
        };
    }

    static getInstance(): LoggerService {
        if (!LoggerService.instance) {
            LoggerService.instance = new LoggerService();
        }
        return LoggerService.instance;
    }

    // ========================================================================
    // Configuration
    // ========================================================================

    configure(config: Partial<LoggerConfig>): void {
        this.config = { ...this.config, ...config };
    }

    setLevel(level: LogLevel): void {
        this.config.minLevel = level;
    }

    getLevel(): LogLevel {
        return this.config.minLevel;
    }

    // ========================================================================
    // Core Logging Methods
    // ========================================================================

    private shouldLog(level: LogLevel): boolean {
        return LEVEL_PRIORITY[level] >= LEVEL_PRIORITY[this.config.minLevel];
    }

    private formatMessage(level: LogLevel, message: string, context?: string): string {
        const parts: string[] = [];

        if (this.config.enableTimestamps) {
            parts.push(`[${new Date().toISOString().slice(11, 23)}]`);
        }

        parts.push(`[${level.toUpperCase()}]`);

        if (context && this.config.enableContext) {
            parts.push(`[${context}]`);
        }

        parts.push(message);

        return parts.join(' ');
    }

    private storeEntry(entry: LogEntry): void {
        this.entries.push(entry);
        if (this.entries.length > this.config.maxStoredEntries) {
            this.entries.shift();
        }
    }

    private log(level: LogLevel, message: string, context?: string, data?: unknown): void {
        if (!this.shouldLog(level)) return;

        const entry: LogEntry = {
            timestamp: new Date().toISOString(),
            level,
            message,
            context,
            data
        };

        this.storeEntry(entry);

        const formattedMessage = this.formatMessage(level, message, context);

        switch (level) {
            case 'debug':
                console.debug(formattedMessage, data !== undefined ? data : '');
                break;
            case 'info':
                console.info(formattedMessage, data !== undefined ? data : '');
                break;
            case 'warn':
                console.warn(formattedMessage, data !== undefined ? data : '');
                break;
            case 'error':
                console.error(formattedMessage, data !== undefined ? data : '');
                break;
        }
    }

    // ========================================================================
    // Public API
    // ========================================================================

    debug(message: string, data?: unknown): void;
    debug(context: string, message: string, data?: unknown): void;
    debug(arg1: string, arg2?: unknown, arg3?: unknown): void {
        if (typeof arg2 === 'string') {
            this.log('debug', arg2, arg1, arg3);
        } else {
            this.log('debug', arg1, undefined, arg2);
        }
    }

    info(message: string, data?: unknown): void;
    info(context: string, message: string, data?: unknown): void;
    info(arg1: string, arg2?: unknown, arg3?: unknown): void {
        if (typeof arg2 === 'string') {
            this.log('info', arg2, arg1, arg3);
        } else {
            this.log('info', arg1, undefined, arg2);
        }
    }

    warn(message: string, data?: unknown): void;
    warn(context: string, message: string, data?: unknown): void;
    warn(arg1: string, arg2?: unknown, arg3?: unknown): void {
        if (typeof arg2 === 'string') {
            this.log('warn', arg2, arg1, arg3);
        } else {
            this.log('warn', arg1, undefined, arg2);
        }
    }

    error(message: string, data?: unknown): void;
    error(context: string, message: string, data?: unknown): void;
    error(arg1: string, arg2?: unknown, arg3?: unknown): void {
        if (typeof arg2 === 'string') {
            this.log('error', arg2, arg1, arg3);
        } else {
            this.log('error', arg1, undefined, arg2);
        }
    }

    // ========================================================================
    // Utility Methods
    // ========================================================================

    /**
     * Create a child logger with a fixed context
     */
    child(context: string): ChildLogger {
        return new ChildLogger(this, context);
    }

    /**
     * Get all stored log entries
     */
    getEntries(): LogEntry[] {
        return [...this.entries];
    }

    /**
     * Clear stored entries
     */
    clearEntries(): void {
        this.entries = [];
    }

    /**
     * Time a function execution
     */
    async time<T>(label: string, fn: () => Promise<T>): Promise<T> {
        const start = performance.now();
        try {
            const result = await fn();
            const duration = performance.now() - start;
            this.debug(`${label} completed in ${duration.toFixed(2)}ms`);
            return result;
        } catch (error) {
            const duration = performance.now() - start;
            this.error(`${label} failed after ${duration.toFixed(2)}ms`, error);
            throw error;
        }
    }
}

// ============================================================================
// Child Logger (with fixed context)
// ============================================================================

class ChildLogger {
    constructor(
        private parent: LoggerService,
        private context: string
    ) { }

    debug(message: string, data?: unknown): void {
        this.parent.debug(this.context, message, data);
    }

    info(message: string, data?: unknown): void {
        this.parent.info(this.context, message, data);
    }

    warn(message: string, data?: unknown): void {
        this.parent.warn(this.context, message, data);
    }

    error(message: string, data?: unknown): void {
        this.parent.error(this.context, message, data);
    }
}

// ============================================================================
// Exports
// ============================================================================

export const logger = LoggerService.getInstance();

// Convenience exports for common patterns
export const log = {
    debug: logger.debug.bind(logger),
    info: logger.info.bind(logger),
    warn: logger.warn.bind(logger),
    error: logger.error.bind(logger)
};

