                                <div className={clsx(
                                    "relative z-10 w-6 h-6 rounded-full border-4 border-white shadow-sm mt-1 flex-shrink-0",
                                    isAdmission ? "bg-emerald-500" :
                                        isDischarge ? "bg-rose-500" :
                                            isTransfer ? "bg-amber-500" :
                                                isDevice ? "bg-cyan-500" :
