/**
 * Transfer Management View
 * Main view for managing patient transfer requests
 */

import React, { useState } from 'react';
import { TransferTable } from './components/TransferTable';
import { TransferFormModal } from './components/TransferFormModal';
import { StatusChangeModal } from './components/StatusChangeModal';
import { ConfirmTransferModal } from './components/ConfirmTransferModal';
import { CancelTransferModal } from './components/CancelTransferModal';
import { TransferQuestionnaireModal } from './components/TransferQuestionnaireModal';
import { TransferDocumentPackageModal } from './components/TransferDocumentPackageModal';
import { TransferRequest, TransferFormData } from '@/types/transfers';
import { QuestionnaireResponse, TransferPatientData, GeneratedDocument } from '@/types/transferDocuments';
import { useTransferManagement } from '@/hooks/useTransferManagement';
import { useDailyRecordData } from '@/context/DailyRecordContext';
import { getHospitalConfigById } from '@/constants/hospitalConfigs';
import { generateTransferDocuments } from '@/services/transfers/documentGeneratorService';

export const TransferManagementView: React.FC = () => {
    const {
        transfers,
        isLoading,
        error,
        createTransfer,
        updateTransfer,
        advanceStatus,
        setTransferStatus,
        markAsTransferred,
        cancelTransfer,
        undoTransfer,
        archiveTransfer,
        deleteHistoryEntry,
        getHospitalizedPatients,
        activeCount
    } = useTransferManagement();

    // Get current daily record to access up-to-date patient data (including birthDate)
    const { record } = useDailyRecordData();

    // Modal states
    const [isFormModalOpen, setIsFormModalOpen] = useState(false);
    const [isStatusModalOpen, setIsStatusModalOpen] = useState(false);
    const [isTransferModalOpen, setIsTransferModalOpen] = useState(false);
    const [isCancelModalOpen, setIsCancelModalOpen] = useState(false);
    const [isQuestionnaireOpen, setIsQuestionnaireOpen] = useState(false);
    const [isPackageModalOpen, setIsPackageModalOpen] = useState(false);
    const [selectedTransfer, setSelectedTransfer] = useState<TransferRequest | null>(null);
    const [selectedHospitalId, setSelectedHospitalId] = useState<string>('');
    const [isGenerating, setIsGenerating] = useState(false);
    const [generatedDocs, setGeneratedDocs] = useState<GeneratedDocument[]>([]);
    const [patientDataForDocs, setPatientDataForDocs] = useState<TransferPatientData | null>(null);

    // Available hospitals for document generation
    // const hospitals = getHospitalConfigs();

    // Form Modal handlers
    const handleNewRequest = () => {
        setSelectedTransfer(null);
        setIsFormModalOpen(true);
    };

    const handleEditTransfer = (transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setIsFormModalOpen(true);
    };

    const handleCloseFormModal = () => {
        setIsFormModalOpen(false);
        setSelectedTransfer(null);
    };

    const handleSave = async (data: TransferFormData) => {
        if (selectedTransfer) {
            await updateTransfer(selectedTransfer.id, data);
        } else {
            await createTransfer(data);
        }
        handleCloseFormModal();
    };

    // Status Change handlers
    const handleStatusChange = (transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setIsStatusModalOpen(true);
    };

    const handleCloseStatusModal = () => {
        setIsStatusModalOpen(false);
        setSelectedTransfer(null);
    };

    const handleConfirmStatusChange = async (_notes?: string) => {
        if (selectedTransfer) {
            await advanceStatus(selectedTransfer);
        }
    };

    // Transfer Confirmation handlers
    const handleMarkTransferred = (transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setIsTransferModalOpen(true);
    };

    const handleCloseTransferModal = () => {
        setIsTransferModalOpen(false);
        setSelectedTransfer(null);
    };

    const handleConfirmTransfer = async (transferMethod: string) => {
        if (selectedTransfer) {
            await markAsTransferred(selectedTransfer, transferMethod);
        }
    };

    // Cancel handlers
    const handleCancel = (transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setIsCancelModalOpen(true);
    };

    const handleCloseCancelModal = () => {
        setIsCancelModalOpen(false);
        setSelectedTransfer(null);
    };

    const handleConfirmCancel = async (reason: string) => {
        if (selectedTransfer) {
            await cancelTransfer(selectedTransfer, reason);
        }
    };

    // Document generation handlers
    const handleGenerateDocs = (transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setSelectedHospitalId('hospital-salvador'); // Default for now
        setIsQuestionnaireOpen(true);
    };

    const handleCloseQuestionnaire = () => {
        setIsQuestionnaireOpen(false);
        setSelectedTransfer(null);
    };

    const handleQuestionnaireComplete = async (responses: QuestionnaireResponse) => {
        if (!selectedTransfer || !selectedHospitalId) return;

        const hospital = getHospitalConfigById(selectedHospitalId);
        if (!hospital) return;

        setIsGenerating(true);

        try {
            // 1. Persist the responses in Firestore first
            await updateTransfer(selectedTransfer.id, {
                questionnaireResponses: responses
            } as any);

            // 2. Build patient data from transfer snapshot
            // Note: snapshot may have birthDate or just age - also check current census for birthDate
            const snapshot = selectedTransfer.patientSnapshot as any;

            // Try to get birthDate from: 1) snapshot, 2) current census record
            const currentPatient = record?.beds[selectedTransfer.bedId];
            const birthDate = snapshot.birthDate || currentPatient?.birthDate || '';

            const patientData: TransferPatientData = {
                patientName: selectedTransfer.patientSnapshot.name,
                rut: selectedTransfer.patientSnapshot.rut || '',
                birthDate: birthDate,
                age: selectedTransfer.patientSnapshot.age, // Direct age from snapshot
                diagnosis: selectedTransfer.patientSnapshot.diagnosis,
                admissionDate: selectedTransfer.patientSnapshot.admissionDate,
                bedName: selectedTransfer.bedId.replace('BED_', ''),
                bedType: 'Básica',
                isUPC: false,
                originHospital: 'Hospital Hanga Roa'
            };

            // 3. Generate documents
            const documents = await generateTransferDocuments(patientData, responses, hospital);

            // 4. Update state to show package modal instead of auto-downloading
            setGeneratedDocs(documents);
            setPatientDataForDocs(patientData);
            setIsQuestionnaireOpen(false);
            setIsPackageModalOpen(true);

        } catch (error) {
            console.error('Error generating documents:', error);
            alert('Error al generar documentos. Por favor intente nuevamente.');
        } finally {
            setIsGenerating(false);
        }
    };

    const handleClosePackageModal = () => {
        setIsPackageModalOpen(false);
        setSelectedTransfer(null);
        setGeneratedDocs([]);
    };

    const handleViewDocs = async (transfer: TransferRequest) => {
        if (!transfer.questionnaireResponses) return;

        setSelectedTransfer(transfer);
        setSelectedHospitalId('hospital-salvador'); // Default

        // Use the same logic as handleQuestionnaireComplete but skipping the modal
        await handleQuestionnaireComplete(transfer.questionnaireResponses);
    };



    return (
        <div className="p-4 max-w-7xl mx-auto">
            {/* Header */}
            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                    <h1 className="text-2xl font-bold text-gray-800">
                        Gestión de Traslados
                    </h1>
                    <span className="px-3 py-1 text-sm font-medium bg-blue-100 text-blue-800 rounded-full">
                        {activeCount} activos
                    </span>
                </div>
                <button
                    onClick={handleNewRequest}
                    className="px-3 py-1.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors flex items-center gap-1.5 text-sm font-medium shadow-sm"
                >
                    <span className="text-lg">+</span>
                    Nueva Solicitud
                </button>
            </div>

            {/* Error Message */}
            {error && (
                <div className="mb-4 p-3 bg-red-100 text-red-700 rounded-lg">
                    {error}
                </div>
            )}

            {/* Loading State */}
            {isLoading ? (
                <div className="text-center py-12 text-gray-500">
                    Cargando solicitudes de traslado...
                </div>
            ) : (
                /* Table */
                <TransferTable
                    transfers={transfers}
                    onEdit={handleEditTransfer}
                    onStatusChange={handleStatusChange}
                    onQuickStatusChange={setTransferStatus}
                    onMarkTransferred={handleMarkTransferred}
                    onCancel={handleCancel}
                    onGenerateDocs={handleGenerateDocs}
                    onViewDocs={handleViewDocs}
                    onUndo={undoTransfer}
                    onArchive={archiveTransfer}
                    onDeleteHistoryEntry={deleteHistoryEntry}
                />
            )}

            {/* Form Modal */}
            {isFormModalOpen && (
                <TransferFormModal
                    transfer={selectedTransfer}
                    patients={getHospitalizedPatients()}
                    onClose={handleCloseFormModal}
                    onSave={handleSave}
                />
            )}

            {/* Status Change Modal */}
            {isStatusModalOpen && selectedTransfer && (
                <StatusChangeModal
                    transfer={selectedTransfer}
                    onClose={handleCloseStatusModal}
                    onConfirm={handleConfirmStatusChange}
                />
            )}

            {/* Transfer Confirmation Modal */}
            {isTransferModalOpen && selectedTransfer && (
                <ConfirmTransferModal
                    transfer={selectedTransfer}
                    onClose={handleCloseTransferModal}
                    onConfirm={handleConfirmTransfer}
                />
            )}

            {/* Cancel Modal */}
            {isCancelModalOpen && selectedTransfer && (
                <CancelTransferModal
                    transfer={selectedTransfer}
                    onClose={handleCloseCancelModal}
                    onConfirm={handleConfirmCancel}
                />
            )}

            {/* Document Questionnaire Modal */}
            {isQuestionnaireOpen && selectedTransfer && getHospitalConfigById(selectedHospitalId) && (
                <TransferQuestionnaireModal
                    isOpen={isQuestionnaireOpen}
                    hospital={getHospitalConfigById(selectedHospitalId)!}
                    patientData={{
                        patientName: selectedTransfer.patientSnapshot.name,
                        rut: selectedTransfer.patientSnapshot.rut,
                        admissionDate: selectedTransfer.patientSnapshot.admissionDate,
                        diagnosis: selectedTransfer.patientSnapshot.diagnosis,
                        bedName: selectedTransfer.bedId.replace('BED_', ''),
                        bedType: 'Básica',
                        isUPC: false,
                        originHospital: 'Hospital Hanga Roa'
                    }}
                    onClose={handleCloseQuestionnaire}
                    initialResponses={selectedTransfer.questionnaireResponses}
                    onComplete={handleQuestionnaireComplete}
                />
            )}

            {/* Document Package Modal */}
            {isPackageModalOpen && selectedTransfer && patientDataForDocs && (
                <TransferDocumentPackageModal
                    isOpen={isPackageModalOpen}
                    hospital={getHospitalConfigById(selectedHospitalId)!}
                    patientData={patientDataForDocs}
                    documents={generatedDocs}
                    onClose={handleClosePackageModal}
                />
            )}

            {/* Generating Overlay */}
            {isGenerating && (
                <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/30 backdrop-blur-md">
                    <div className="bg-white px-8 py-6 rounded-2xl shadow-xl flex flex-col items-center gap-4">
                        <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
                        <p className="font-semibold text-slate-700">Preparando documentos...</p>
                        <p className="text-sm text-slate-500 italic">Por favor espere un momento</p>
                    </div>
                </div>
            )}
        </div>
    );
};

export default TransferManagementView;

import React, { useState } from 'react';
import { X, FileText, Download, Edit3, CheckCircle2, AlertCircle, Loader2 } from 'lucide-react';
import { HospitalConfig, GeneratedDocument, TransferPatientData } from '@/types/transferDocuments';
import { downloadDocument } from '@/services/transfers/documentGeneratorService';
import { uploadToTransferFolder, makeFilePubliclyEditable } from '@/services/google/googleDriveService';
import clsx from 'clsx';

interface TransferDocumentPackageModalProps {
    isOpen: boolean;
    onClose: () => void;
    hospital: HospitalConfig;
    patientData: TransferPatientData;
    documents: GeneratedDocument[];
    onEdit?: (doc: GeneratedDocument) => void;
}

export const TransferDocumentPackageModal: React.FC<TransferDocumentPackageModalProps> = ({
    isOpen,
    onClose,
    hospital,
    patientData,
    documents
}) => {
    const [isUploading, setIsUploading] = useState<string | null>(null);

    if (!isOpen) return null;

    const handleEdit = async (doc: GeneratedDocument) => {
        setIsUploading(doc.templateId);
        try {
            // Upload to organized folder structure: Traslados HHR / Año / Mes / Paciente
            const result = await uploadToTransferFolder(doc.blob, doc.fileName, {
                patientName: patientData.patientName,
                patientRut: patientData.rut
            });
            // console.info(`[Transfers] File uploaded to: ${result.folderPath}`);

            // Optional: make it editable by anyone with link if corporate account allows it
            await makeFilePubliclyEditable(result.fileId);
            window.open(result.webViewLink, '_blank');
        } catch (error: any) {
            console.error('Error editing document:', error);
            const msg = error.message || 'Error al conectar con Google Drive';
            if (msg.includes('configured')) {
                alert('La edición online no está configurada aún (falta Client ID). Por favor, descarga el archivo para editarlo localmente.');
            } else {
                alert(msg);
            }
        } finally {
            setIsUploading(null);
        }
    };

    return (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/30 backdrop-blur-md p-4">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-3xl max-h-[90vh] flex flex-col overflow-hidden animate-in fade-in zoom-in duration-200">
                {/* Header */}
                <div className="px-5 py-3 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
                    <div>
                        <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                            <CheckCircle2 className="text-green-600" size={20} />
                            Documentos Listos
                        </h2>
                        <p className="text-slate-500 text-xs">
                            {hospital.name} • {patientData.patientName}
                        </p>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-1.5 rounded-full hover:bg-slate-200 transition-colors"
                    >
                        <X size={18} className="text-slate-500" />
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-4 bg-slate-50/30">
                    <div className="grid gap-3">
                        {documents.map((doc) => (
                            <div
                                key={doc.templateId}
                                className="bg-white border border-slate-200 rounded-lg p-3 flex items-center justify-between shadow-sm hover:shadow-md transition-shadow"
                            >
                                <div className="flex items-center gap-3 shrink min-w-0">
                                    <div className={clsx(
                                        "w-10 h-10 rounded-lg flex items-center justify-center shrink-0",
                                        doc.mimeType.includes('spreadsheet') ? "bg-green-50 text-green-600" : "bg-blue-50 text-blue-600"
                                    )}>
                                        <FileText size={20} />
                                    </div>
                                    <div className="min-w-0">
                                        <h3 className="font-semibold text-slate-800 truncate text-sm">
                                            {doc.fileName}
                                        </h3>
                                        <p className="text-[10px] text-slate-400 uppercase tracking-widest mt-0.5 truncate">
                                            {doc.templateId.replace(/-/g, ' ')}
                                        </p>
                                    </div>
                                </div>

                                <div className="flex items-center gap-2 shrink-0">
                                    <button
                                        onClick={() => handleEdit(doc)}
                                        disabled={!!isUploading}
                                        className={clsx(
                                            "flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg transition-colors border border-transparent min-w-[100px] justify-center",
                                            isUploading === doc.templateId
                                                ? "bg-blue-50 text-blue-400 cursor-not-allowed"
                                                : "text-blue-600 hover:bg-blue-50 hover:border-blue-100"
                                        )}
                                    >
                                        {isUploading === doc.templateId ? (
                                            <Loader2 size={14} className="animate-spin" />
                                        ) : (
                                            <Edit3 size={14} />
                                        )}
                                        {isUploading === doc.templateId ? 'Subiendo...' : 'Editar'}
                                    </button>
                                    <button
                                        onClick={() => downloadDocument(doc)}
                                        disabled={!!isUploading}
                                        className={clsx(
                                            "flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium bg-slate-800 text-white rounded-lg transition-colors shadow-sm",
                                            isUploading ? "opacity-50 cursor-not-allowed" : "hover:bg-slate-900"
                                        )}
                                    >
                                        <Download size={14} />
                                        Descargar
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>

                    {/* Info Box */}
                    <div className="mt-6 p-3 bg-blue-50/50 border border-blue-100 rounded-lg flex gap-2">
                        <AlertCircle className="text-blue-600 shrink-0" size={16} />
                        <div className="text-[11px] text-blue-800">
                            <p className="font-semibold">Sugerencia de Edición</p>
                            <p className="mt-0.5 opacity-90">
                                Al pulsar &quot;Editar&quot;, el documento se abrirá en Google Drive. Cualquier cambio que realices se guardará automáticamente en la nube.
                            </p>
                        </div>
                    </div>
                </div>

                {/* Footer */}
                <div className="px-6 py-4 border-t border-slate-200 bg-white flex justify-end">
                    <button
                        onClick={onClose}
                        className="px-6 py-2 bg-slate-100 text-slate-700 font-medium rounded-lg hover:bg-slate-200 transition-colors"
                    >
                        Finalizar
                    </button>
                </div>
            </div>
        </div>
    );
};

export default TransferDocumentPackageModal;

/**
 * WhatsApp Configuration Panel
 * 
 * Admin panel for configuring WhatsApp integration settings.
 * Refactored to use TanStack Query for state management.
 */

import React, { useState } from 'react';
import {
    MessageSquare,
    Clock,
    Users,
    Check,
    RefreshCw,
    Wifi,
    WifiOff,
    Save,
    AlertCircle
} from 'lucide-react';
import {
    useWhatsAppConfigQuery,
    useWhatsAppHealthQuery,
    useWhatsAppGroupsQuery,
    useUpdateWhatsAppConfigMutation
} from '@/hooks/useWhatsAppQuery';
import type { WhatsAppConfig } from '@/types';

export const WhatsAppConfigView: React.FC = () => {
    // 1. Data Queries
    const {
        data: serverConfig,
        isLoading: loadingConfig,
        refetch: refetchConfig
    } = useWhatsAppConfigQuery();

    const {
        data: botStatus = 'disconnected',
        isLoading: checkingHealth,
        refetch: refetchHealth
    } = useWhatsAppHealthQuery();

    const loading = loadingConfig || (checkingHealth && botStatus === 'disconnected');

    const handleRefresh = async () => {
        await Promise.all([refetchConfig(), refetchHealth()]);
    };

    if (loading || !serverConfig) {
        return (
            <div className="flex items-center justify-center py-12">
                <RefreshCw className="w-8 h-8 animate-spin text-blue-500" />
            </div>
        );
    }

    return (
        <WhatsAppConfigForm
            initialConfig={serverConfig}
            botStatus={botStatus}
            onRefresh={handleRefresh}
            refreshing={loading}
        />
    );
};

interface WhatsAppConfigFormProps {
    initialConfig: WhatsAppConfig;
    botStatus: string;
    onRefresh: () => void;
    refreshing: boolean;
}

const WhatsAppConfigForm: React.FC<WhatsAppConfigFormProps> = ({ initialConfig, botStatus, onRefresh, refreshing }) => {
    const {
        data: groups = [],
        isLoading: loadingGroups
    } = useWhatsAppGroupsQuery(botStatus === 'connected');

    const updateConfigMutation = useUpdateWhatsAppConfigMutation();

    // Clean initialization from props - NO useEffect needed!
    const [localConfig, setLocalConfig] = useState<WhatsAppConfig>(initialConfig);
    const [autoSendTime, setAutoSendTime] = useState(initialConfig.handoffNotifications?.autoSendTime || '17:00');

    const handleSave = async () => {
        const updated: Partial<WhatsAppConfig> = {
            ...localConfig,
            handoffNotifications: {
                ...localConfig.handoffNotifications,
                autoSendTime
            }
        };

        updateConfigMutation.mutate(updated);
    };

    const handleGroupChange = (type: 'shift' | 'handoff', groupId: string) => {
        if (type === 'shift') {
            setLocalConfig({
                ...localConfig,
                shiftParser: { ...localConfig.shiftParser, sourceGroupId: groupId }
            });
        } else {
            setLocalConfig({
                ...localConfig,
                handoffNotifications: { ...localConfig.handoffNotifications, targetGroupId: groupId }
            });
        }
    };

    const saving = updateConfigMutation.isPending;

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <MessageSquare className="w-6 h-6 text-green-500" />
                    <h2 className="text-xl font-semibold">Configuración WhatsApp</h2>
                </div>
                <button
                    onClick={onRefresh}
                    className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
                    title="Actualizar"
                    disabled={refreshing}
                >
                    <RefreshCw className={clsx("w-5 h-5", refreshing && "animate-spin")} />
                </button>
            </div>

            {/* Bot Status Card */}
            <div className={`p-4 rounded-lg border-2 ${botStatus === 'connected'
                ? 'border-green-200 bg-green-50'
                : 'border-red-200 bg-red-50'
                }`}>
                <div className="flex items-center gap-3">
                    {botStatus === 'connected' ? (
                        <Wifi className="w-6 h-6 text-green-600" />
                    ) : (
                        <WifiOff className="w-6 h-6 text-red-600" />
                    )}
                    <div>
                        <h3 className="font-medium">
                            Estado del Bot: {botStatus === 'connected' ? 'Conectado' : 'Desconectado'}
                        </h3>
                        <p className="text-sm text-gray-600">
                            {botStatus === 'connected'
                                ? 'El bot está activo y escuchando mensajes'
                                : 'Verifica que el servidor del bot esté corriendo'}
                        </p>
                    </div>
                </div>
            </div>

            {/* Configuration Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

                {/* Shift Parser Config */}
                <div className="bg-white border rounded-lg p-5 shadow-sm">
                    <div className="flex items-center gap-2 mb-4">
                        <Users className="w-5 h-5 text-blue-500" />
                        <h3 className="font-medium">Parser de Turnos</h3>
                    </div>

                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <span className="text-sm">Activado</span>
                            <button
                                onClick={() => setLocalConfig({
                                    ...localConfig,
                                    shiftParser: { ...localConfig.shiftParser, enabled: !localConfig.shiftParser.enabled }
                                })}
                                className={`w-12 h-6 rounded-full transition-colors ${localConfig.shiftParser.enabled ? 'bg-green-500' : 'bg-gray-300'
                                    }`}
                            >
                                <div className={`w-5 h-5 rounded-full bg-white shadow transform transition-transform ${localConfig.shiftParser.enabled ? 'translate-x-6' : 'translate-x-0.5'
                                    }`} />
                            </button>
                        </div>

                        <div>
                            <label className="block text-sm text-gray-600 mb-1">
                                Grupo de Turnos (solo lectura)
                            </label>
                            <select
                                value={localConfig.shiftParser.sourceGroupId || ''}
                                onChange={(e) => handleGroupChange('shift', e.target.value)}
                                className="w-full p-2 border rounded-lg text-sm"
                                disabled={botStatus !== 'connected' || loadingGroups}
                            >
                                <option value="">{loadingGroups ? 'Cargando grupos...' : 'Seleccionar grupo...'}</option>
                                {groups.map(g => (
                                    <option key={g.id} value={g.id}>{g.name}</option>
                                ))}
                            </select>
                        </div>
                    </div>
                </div>

                {/* Handoff Notifications Config */}
                <div className="bg-white border rounded-lg p-5 shadow-sm">
                    <div className="flex items-center gap-2 mb-4">
                        <MessageSquare className="w-5 h-5 text-green-500" />
                        <h3 className="font-medium">Notificaciones de Entrega</h3>
                    </div>

                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <span className="text-sm">Activado</span>
                            <button
                                onClick={() => setLocalConfig({
                                    ...localConfig,
                                    handoffNotifications: {
                                        ...localConfig.handoffNotifications,
                                        enabled: !localConfig.handoffNotifications.enabled
                                    }
                                })}
                                className={`w-12 h-6 rounded-full transition-colors ${localConfig.handoffNotifications.enabled ? 'bg-green-500' : 'bg-gray-300'
                                    }`}
                            >
                                <div className={`w-5 h-5 rounded-full bg-white shadow transform transition-transform ${localConfig.handoffNotifications.enabled ? 'translate-x-6' : 'translate-x-0.5'
                                    }`} />
                            </button>
                        </div>

                        <div>
                            <label className="block text-sm text-gray-600 mb-1">
                                Grupo para Enviar Entregas
                            </label>
                            <select
                                value={localConfig.handoffNotifications.targetGroupId || ''}
                                onChange={(e) => handleGroupChange('handoff', e.target.value)}
                                className="w-full p-2 border rounded-lg text-sm"
                                disabled={botStatus !== 'connected' || loadingGroups}
                            >
                                <option value="">{loadingGroups ? 'Cargando grupos...' : 'Seleccionar grupo...'}</option>
                                {groups.map(g => (
                                    <option key={g.id} value={g.id}>{g.name}</option>
                                ))}
                            </select>
                        </div>
                    </div>
                </div>
            </div>

            {/* Auto-Send Schedule */}
            <div className="bg-white border rounded-lg p-5 shadow-sm">
                <div className="flex items-center gap-2 mb-4">
                    <Clock className="w-5 h-5 text-orange-500" />
                    <h3 className="font-medium">Envío Automático</h3>
                </div>

                <div className="flex items-center gap-4">
                    <div>
                        <label className="block text-sm text-gray-600 mb-1">
                            Hora de envío automático
                        </label>
                        <input
                            type="time"
                            value={autoSendTime}
                            onChange={(e) => setAutoSendTime(e.target.value)}
                            className="p-2 border rounded-lg"
                        />
                    </div>
                    <div className="text-sm text-gray-500 mt-5">
                        Si no se envía manualmente, el sistema enviará automáticamente a las {autoSendTime}
                    </div>
                </div>
            </div>

            {/* Save Button & Status */}
            <div className="flex items-center justify-end gap-4">
                {updateConfigMutation.isSuccess && (
                    <div className="flex items-center gap-1.5 text-xs text-green-600 font-bold animate-pulse">
                        <Check size={14} />
                        GUARDADO CORRECTAMENTE
                    </div>
                )}
                {updateConfigMutation.isError && (
                    <div className="flex items-center gap-1.5 text-xs text-red-600 font-bold">
                        <AlertCircle size={14} />
                        FALLÓ EL GUARDADO
                    </div>
                )}
                <button
                    onClick={handleSave}
                    disabled={saving}
                    className="flex items-center gap-2 px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 transition-colors shadow-lg shadow-blue-200"
                >
                    {saving ? (
                        <RefreshCw className="w-4 h-4 animate-spin" />
                    ) : (
                        <Save className="w-4 h-4" />
                    )}
                    Guardar Configuración
                </button>
            </div>
        </div>
    );
};

// Internal utility for class names
const clsx = (...classes: any[]) => classes.filter(Boolean).join(' ');

export default WhatsAppConfigView;
